INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 1, 'HUBO un varón en tierra de Hus, llamado Job; y era este hombre perfecto y recto, y temeroso de Dios, y apartado del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 2, 'Y naciéronle siete hijos y tres hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 3, 'Y su hacienda era siete mil ovejas, y tres mil camellos, y quinientas yuntas de bueyes, y quinientas asnas, y muchísimos criados: y era aquel varón grande más que todos los Orientales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 4, 'E iban sus hijos y hacían banquetes en sus casas, cada uno en su día; y enviaban á llamar sus tres hermanas, para que comiesen y bebiesen con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 5, 'Y acontecía que, habiendo pasado en turno los días del convite, Job enviaba y santificábalos, y levantábase de mañana y ofrecía holocaustos conforme al número de todos ellos. Porque decía Job: Quizá habrán pecado mis hijos, y habrán blasfemado á Dios en sus corazones. De esta manera hacía todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 6, 'Y un día vinieron los hijos de Dios á presentarse delante de Jehová, entre los cuales vino también Satán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 7, 'Y dijo Jehová á Satán: ¿De dónde vienes? Y respondiendo Satán á Jehová, dijo: De rodear la tierra, y de andar por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 8, 'Y Jehová dijo á Satán: ¿No has considerado á mi siervo Job, que no hay otro como él en la tierra, varón perfecto y recto, temeroso de Dios, y apartado de mal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 9, 'Y respondiendo Satán á Jehová, dijo: ¿Teme Job á Dios de balde?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 10, '¿No le has tú cercado á él, y á su casa, y á todo lo que tiene en derredor? Al trabajo de sus manos has dado bendición; por tanto su hacienda ha crecido sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 11, 'Mas extiende ahora tu mano, y toca á todo lo que tiene, y verás si no te blasfema en tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 12, 'Y dijo Jehová á Satán: He aquí, todo lo que tiene está en tu mano: solamente no pongas tu mano sobre él. Y salióse Satán de delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 13, 'Y un día aconteció que sus hijos é hijas comían y bebían vino en casa de su hermano el primogénito,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 14, 'Y vino un mensajero á Job, que le dijo: Estando arando los bueyes, y las asnas paciendo cerca de ellos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 15, 'Acometieron los Sabeos, y tomáronlos, é hirieron á los mozos á filo de espada: solamente escapé yo para traerte las nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 16, 'Aun estaba éste hablando, y vino otro que dijo: Fuego de Dios cayó del cielo, que quemó las ovejas y los mozos, y los consumió: solamente escapé yo solo para traerte las nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 17, 'Todavía estaba éste hablando, y vino otro que dijo: Los Caldeos hicieron tres escuadrones, y dieron sobre los camellos, y tomáronlos, é hirieron á los mozos á filo de espada; y solamente escapé yo solo para traerte las nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 18, 'Entre tanto que éste hablaba, vino otro que dijo: Tus hijos y tus hijas estaban comiendo y bebiendo vino en casa de su hermano el primogénito;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 19, 'Y he aquí un gran viento que vino del lado del desierto, é hirió las cuatro esquinas de la casa, y cayó sobre los mozos, y murieron; y solamente escapé yo solo para traerte las nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 20, 'Entonces Job se levantó, y rasgó su manto, y trasquiló su cabeza, y cayendo en tierra adoró;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 21, 'Y dijo: Desnudo salí del vientre de mi madre, y desnudo tornaré allá. Jehová dió, y Jehová quitó: sea el nombre de Jehová bendito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 1, 22, 'En todo esto no pecó Job, ni atribuyó á Dios despropósito alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 1, 'Y OTRO día aconteció que vinieron los hijos de Dios para presentarse delante de Jehová, y Satán vino también entre ellos pareciendo delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 2, 'Y dijo Jehová á Satán: ¿De dónde vienes? Respondió Satán á Jehová, y dijo: De rodear la tierra, y de andar por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 3, 'Y Jehová dijo á Satán: ¿No has considerado á mi siervo Job, que no hay otro como él en la tierra, varón perfecto y recto, temeroso de Dios y apartado de mal, y que aun retiene su perfección, habiéndome tú incitado contra él, para que lo arruinara sin causa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 4, 'Y respondiendo Satán dijo á Jehová: Piel por piel, todo lo que el hombre tiene dará por su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 5, 'Mas extiende ahora tu mano, y toca á su hueso y á su carne, y verás si no te blasfema en tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 6, 'Y Jehová dijo á Satán: He aquí, él está en tu mano; mas guarda su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 7, 'Y salió Satán de delante de Jehová, é hirió á Job de una maligna sarna desde la planta de su pie hasta la mollera de su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 8, 'Y tomaba una teja para rascarse con ella, y estaba sentado en medio de ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 9, 'Díjole entonces su mujer: ¿Aun retienes tú tu simplicidad? Bendice á Dios, y muérete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 10, 'Y él le dijo: Como suele hablar cualquiera de las mujeres fatuas, has hablado. También recibimos el bien de Dios, ¿y el mal no recibiremos? En todo esto no pecó Job con sus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 11, 'Y tres amigos de Job, Eliphaz Temanita, y Bildad Suhita, y Sophar Naamathita, luego que oyeron todo este mal que le había sobrevenido, vinieron cada uno de su lugar; porque habían concertado de venir juntos á condolecerse de él, y á consolarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 12, 'Los cuales alzando los ojos desde lejos, no lo conocieron, y lloraron á voz en grito; y cada uno de ellos rasgó su manto, y esparcieron polvo sobre sus cabezas hacia el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 2, 13, 'Así se sentaron con él en tierra por siete días y siete noches, y ninguno le hablaba palabra, porque veían que el dolor era muy grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 1, 'DESPUÉS de esto abrió Job su boca, y maldijo su día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 2, 'Y exclamó Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 3, 'Perezca el día en que yo nací, Y la noche que se dijo: Varón es concebido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 4, 'Sea aquel día sombrío, Y Dios no cuide de él desde arriba, Ni claridad sobre él resplandezca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 5, 'Aféenlo tinieblas y sombra de muerte; Repose sobre él nublado, Que lo haga horrible como caliginoso día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 6, 'Ocupe la oscuridad aquella noche; No sea contada entre los días del año, Ni venga en él número de los meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 7, '¡Oh si fuere aquella noche solitaria, Que no viniera canción alguna en ella!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 8, 'Maldíganla los que maldicen al día, Los que se aprestan para levantar su llanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 9, 'Oscurézcanse las estrellas de su alba; Espere la luz, y no venga, Ni vea los párpados de la mañana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 10, 'Por cuanto no cerró las puertas del vientre donde yo estaba, Ni escondió de mis ojos la miseria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 11, '¿Por qué no morí yo desde la matriz, O fuí traspasado en saliendo del vientre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 12, '¿Por qué me previnieron las rodillas? ¿Y para qué las tetas que mamase?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 13, 'Pues que ahora yaciera yo, y reposara; Durmiera, y entonces tuviera reposo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 14, 'Con los reyes y con los consejeros de la tierra, Que edifican para sí los desiertos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 15, 'O con los príncipes que poseían el oro, Que henchían sus casas de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 16, 'O ¿por qué no fuí escondido como aborto, Como los pequeñitos que nunca vieron luz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 17, 'Allí los impíos dejan el perturbar, Y allí descansan los de cansadas fuerzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 18, 'Allí asimismo reposan los cautivos; No oyen la voz del exactor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 19, 'Allí están el chico y el grande; Y el siervo libre de su señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 20, '¿Por qué se da luz al trabajado, Y vida á los de ánimo en amargura,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 21, 'Que esperan la muerte, y ella no llega, Aunque la buscan más que tesoros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 22, 'Que se alegran sobremanera, Y se gozan, cuando hallan el sepulcro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 23, '¿Por qué al hombre que no sabe por donde vaya, Y al cual Dios ha encerrado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 24, 'Pues antes que mi pan viene mi suspiro; Y mis gemidos corren como aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 25, 'Porque el temor que me espantaba me ha venido, Y hame acontecido lo que temía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 3, 26, 'No he tenido paz, no me aseguré, ni me estuve reposado; Vínome no obstante turbación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 1, 'Y RESPONDIO Eliphaz el Temanita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 2, 'Si probáremos á hablarte, serte ha molesto; Mas ¿quién podrá detener las palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 3, 'He aquí, tú enseñabas á muchos, Y las manos flacas corroborabas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 4, 'Al que vacilaba, enderezaban tus palabras, Y esforzabas las rodillas que decaían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 5, 'Mas ahora que el mal sobre ti ha venido, te es duro; Y cuando ha llegado hasta ti, te turbas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 6, '¿Es este tu temor, tu confianza, Tu esperanza, y la perfección de tus caminos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 7, 'Recapacita ahora, ¿quién que fuera inocente se perdiera? Y ¿en dónde los rectos fueron cortados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 8, 'Como yo he visto, los que aran iniquidad Y siembran injuria, la siegan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 9, 'Perecen por el aliento de Dios, Y por el espíritu de su furor son consumidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 10, 'El bramido del león, y la voz del león, Y los dientes de los leoncillos son quebrantados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 11, 'El león viejo perece por falta de presa, Y los hijos del león son esparcidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 12, 'El negocio también me era á mí oculto; Mas mi oído ha percibido algo de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 13, 'En imaginaciones de visiones nocturnas, Cuando el sueño cae sobre los hombres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 14, 'Sobrevínome un espanto y un temblor, Que estremeció todos mis huesos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 15, 'Y un espíritu pasó por delante de mí, Que hizo se erizara el pelo de mi carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 16, 'Paróse un fantasma delante de mis ojos, Cuyo rostro yo no conocí, Y quedo, oí que decía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 17, '¿Si será el hombre más justo que Dios? ¿Si será el varón más limpio que el que lo hizo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 18, 'He aquí que en sus siervos no confía, Y notó necedad en sus ángeles');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 19, '¡Cuánto más en los que habitan en casas de lodo, Cuyo fundamento está en el polvo, Y que serán quebrantados de la polilla!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 20, 'De la mañana á la tarde son quebrantados, Y se pierden para siempre, sin haber quien lo considere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 4, 21, '¿Su hermosura, no se pierde con ellos mismos? Mueren, y sin sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 1, 'AHORA pues da voces, si habrá quien te responda; ¿Y á cuál de los santos te volverás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 2, 'Es cierto que al necio la ira lo mata, Y al codicioso consume la envidia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 3, 'Yo he visto al necio que echaba raíces, Y en la misma hora maldije su habitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 4, 'Sus hijos estarán lejos de la salud, Y en la puerta serán quebrantados, Y no habrá quien los libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 5, 'Su mies comerán los hambrientos, Y sacaránla de entre las espinas, Y los sedientos beberán su hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 6, 'Porque la iniquidad no sale del polvo, Ni la molestia brota de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 7, 'Empero como las centellas se levantan para volar por el aire, Así el hombre nace para la aflicción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 8, 'Ciertamente yo buscaría á Dios, Y depositaría en él mis negocios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 9, 'El cual hace cosas grandes é inescrutables, Y maravillas que no tienen cuento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 10, 'Que da la lluvia sobre la haz de la tierra, Y envía las aguas por los campos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 11, 'Que pone los humildes en altura, Y los enlutados son levantados á salud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 12, 'Que frustra los pensamientos de los astutos, Para que sus manos no hagan nada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 13, 'Que prende á los sabios en la astucia de ellos, Y el consejo de los perversos es entontecido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 14, 'De día se topan con tinieblas, Y en mitad del día andan á tientas como de noche:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 15, 'Y libra de la espada al pobre, de la boca de los impíos, Y de la mano violenta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 16, 'Pues es esperanza al menesteroso, Y la iniquidad cerrará su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 17, 'He aquí, bienaventurado es el hombre á quien Dios castiga: Por tanto no menosprecies la corrección del Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 18, 'Porque él es el que hace la llaga, y él la vendará: El hiere, y sus manos curan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 19, 'En seis tribulaciones te librará, Y en la séptima no te tocará el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 20, 'En el hambre te redimirá de la muerte, Y en la guerra de las manos de la espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 21, 'Del azote de la lengua serás encubierto; Ni temerás de la destrucción cuando viniere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 22, 'De la destrucción y del hambre te reirás, Y no temerás de las bestias del campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 23, 'Pues aun con las piedras del campo tendrás tu concierto, Y las bestias del campo te serán pacíficas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 24, 'Y sabrás que hay paz en tu tienda; Y visitarás tu morada, y no pecarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 25, 'Asimismo echarás de ver que tu simiente es mucha, Y tu prole como la hierba de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 26, 'Y vendrás en la vejez á la sepultura, Como el montón de trigo que se coge á su tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 5, 27, 'He aquí lo que hemos inquirido, lo cual es así: Oyelo, y juzga tú para contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 1, 'Y RESPONDIO Job y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 2, '¡Oh si pesasen al justo mi queja y mi tormento, Y se alzasen igualmente en balanza!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 3, 'Porque pesaría aquél más que la arena del mar: Y por tanto mis palabras son cortadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 4, 'Porque las saetas del Todopoderoso están en mí, Cuyo veneno bebe mi espíritu; Y terrores de Dios me combaten.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 5, '¿Acaso gime el asno montés junto á la hierba? ¿Muge el buey junto á su pasto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 6, '¿Comeráse lo desabrido sin sal? ¿O habrá gusto en la clara del huevo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 7, 'Las cosas que mi alma no quería tocar, Por los dolores son mi comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 8, '¡Quién me diera que viniese mi petición, Y que Dios me otorgase lo que espero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 9, 'Y que pluguiera á Dios quebrantarme; Que soltara su mano, y me deshiciera!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 10, 'Y sería aún mi consuelo, Si me asaltase con dolor sin dar más tregua, Que yo no he escondido las palabras del Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 11, '¿Cuál es mi fortaleza para esperar aún? ¿Y cuál mi fin para dilatar mi vida?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 12, '¿Es mi fortaleza la de las piedras? ¿O mi carne, es de acero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 13, '¿No me ayudo cuanto puedo, Y el poder me falta del todo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 14, 'El atribulado es consolado de su compañero: Mas hase abandonado el temor del Omnipotente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 15, 'Mis hermanos han mentido cual arroyo: Pasáronse como corrientes impetuosas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 16, 'Que están escondidas por la helada, Y encubiertas con nieve;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 17, 'Que al tiempo del calor son deshechas, Y en calentándose, desaparecen de su lugar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 18, 'Apártanse de la senda de su rumbo, Van menguando y piérdense.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 19, 'Miraron los caminantes de Temán, Los caminantes de Saba esperaron en ellas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 20, 'Mas fueron avergonzados por su esperanza; Porque vinieron hasta ellas, y halláronse confusos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 21, 'Ahora ciertamente como ellas sois vosotros: Que habéis visto el tormento, y teméis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 22, '¿Os he dicho yo: Traedme, Y pagad por mí de vuestra hacienda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 23, 'Y libradme de la mano del opresor, Y redimidme del poder de los violentos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 24, 'Enseñadme, y yo callaré: Y hacedme entender en qué he errado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 25, '¡Cuán fuertes son las palabras de rectitud! Mas ¿qué reprende el que reprende de vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 26, '¿Pensáis censurar palabras, Y los discursos de un desesperado, que son como el viento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 27, 'También os arrojáis sobre el huérfano, Y hacéis hoyo delante de vuestro amigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 28, 'Ahora pues, si queréis, mirad en mí, Y ved si miento delante de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 29, 'Tornad ahora, y no haya iniquidad; Volved aún á considerar mi justicia en esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 6, 30, '¿Hay iniquidad en mi lengua? ¿No puede mi paladar discernir las cosas depravadas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 1, 'CIERTAMENTE tiempo limitado tiene el hombre sobre la tierra, Y sus días son como los días del jornalero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 2, 'Como el siervo anhela la sombra, Y como el jornalero espera el reposo de su trabajo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 3, 'Así poseo yo meses de vanidad, Y noches de trabajo me dieron por cuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 4, 'Cuando estoy acostado, digo: ¿Cuándo me levantaré? Y mide mi corazón la noche, Y estoy harto de devaneos hasta el alba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 5, 'Mi carne está vestida de gusanos, y de costras de polvo; Mi piel hendida y abominable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 6, 'Y mis días fueron más ligeros que la lanzadera del tejedor, Y fenecieron sin esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 7, 'Acuérdate que mi vida es viento, Y que mis ojos no volverán á ver el bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 8, 'Los ojos de los que me ven, no me verán más: Tus ojos sobre mí, y dejaré de ser.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 9, 'La nube se consume, y se va: Así el que desciende al sepulcro no subirá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 10, 'No tornará más á su casa, Ni su lugar le conocerá más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 11, 'Por tanto yo no reprimiré mi boca; Hablaré en la angustia de mi espíritu, Y quejaréme con la amargura de mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 12, '¿Soy yo la mar, ó ballena, Que me pongas guarda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 13, 'Cuando digo: Mi cama me consolará, Mi cama atenuará mis quejas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 14, 'Entonces me quebrantarás con sueños, Y me turbarás con visiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 15, 'Y así mi alma tuvo por mejor el ahogamiento, Y quiso la muerte más que mis huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 16, 'Aburríme: no he de vivir yo para siempre; Déjáme, pues que mis días son vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 17, '¿Qué es el hombre, para que lo engrandezcas, Y que pongas sobre él tu corazón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 18, 'Y lo visites todas las mañanas, Y todos los momentos lo pruebes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 19, '¿Hasta cuándo no me dejarás, Ni me soltarás hasta que trague mi saliva?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 20, 'Pequé, ¿qué te haré, oh Guarda de los hombres? ¿Por qué me has puesto contrario á ti, Y que á mí mismo sea pesado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 7, 21, '¿Y por qué no quitas mi rebelión, y perdonas mi iniquidad? Porque ahora dormiré en el polvo, Y si me buscares de mañana, ya no seré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 1, 'Y RESPONDIO Bildad Suhita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 2, '¿Hasta cuándo hablarás tales cosas, Y las palabras de tu boca serán como un viento fuerte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 3, '¿Acaso pervertirá Dios el derecho, O el Todopoderoso pervertirá la justicia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 4, 'Si tus hijos pecaron contra él, El los echó en el lugar de su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 5, 'Si tú de mañana buscares á Dios, Y rogares al Todopoderoso;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 6, 'Si fueres limpio y derecho, Cierto luego se despertará sobre ti, Y hará próspera la morada de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 7, 'Y tu principio habrá sido pequeño, Y tu postrimería acrecerá en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 8, 'Porque pregunta ahora á la edad pasada, Y disponte para inquirir de sus padres de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 9, 'Pues nosotros somos de ayer, y no sabemos, Siendo nuestros días sobre la tierra como sombra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 10, '¿No te enseñarán ellos, te dirán, Y de su corazón sacarán palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 11, '¿Crece el junco sin lodo? ¿Crece el prado sin agua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 12, 'Aun él en su verdor no será cortado, Y antes de toda hierba se secará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 13, 'Tales son los caminos de todos los que olvidan á Dios: Y la esperanza del impío perecerá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 14, 'Porque su esperanza será cortada, Y su confianza es casa de araña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 15, 'Apoyaráse él sobre su casa, mas no permanecerá en pie; Atendráse á ella, mas no se afirmará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 16, 'A manera de un árbol, está verde delante del sol, Y sus renuevos salen sobre su huerto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 17, 'Vanse entretejiendo sus raíces junto á una fuente, Y enlazándose hasta un lugar pedregoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 18, 'Si le arrancaren de su lugar, Este negarále entonces, diciendo: Nunca te vi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 19, 'Ciertamente éste será el gozo de su camino; Y de la tierra de donde se traspusiere, nacerán otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 20, 'He aquí, Dios no aborrece al perfecto, Ni toma la mano de los malignos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 21, 'Aun henchirá tu boca de risa, Y tus labios de júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 8, 22, 'Los que te aborrecen, serán vestidos de confusión; Y la habitación de los impíos perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 2, 'Ciertamente yo conozco que es así: ¿Y cómo se justificará el hombre con Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 3, 'Si quisiere contender con él, No le podrá responder á una cosa de mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 4, 'El es sabio de corazón, y poderoso en fortaleza, ¿Quién se endureció contra él, y quedó en paz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 5, 'Que arranca los montes con su furor, Y no conocen quién los trastornó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 6, 'Que remueve la tierra de su lugar, Y hace temblar sus columnas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 7, 'Que manda al sol, y no sale; Y sella las estrellas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 8, 'El que extiende solo los cielos, Y anda sobre las alturas de la mar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 9, 'El que hizo el Arcturo, y el Orión, y las Pléyadas, Y los lugares secretos del mediodía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 10, 'El que hace cosas grandes é incomprensibles, Y maravillosas, sin número.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 11, 'He aquí que él pasará delante de mí, y yo no lo veré; Y pasará, y no lo entenderé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 12, 'He aquí, arrebatará; ¿quién le hará restituir? ¿Quién le dirá, Qué haces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 13, 'Dios no tornará atrás su ira, Y debajo de él se encorvan los que ayudan á los soberbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 14, '¿Cuánto menos le responderé yo, Y hablaré con él palabras estudiadas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 15, 'Que aunque fuese yo justo, no responderé; Antes habré de rogar á mi juez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 16, 'Que si yo le invocase, y él me respondiese, Aun no creeré que haya escuchado mi voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 17, 'Porque me ha quebrado con tempestad, Y ha aumentado mis heridas sin causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 18, 'No me ha concedido que tome mi aliento; Mas hame hartado de amarguras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 19, 'Si habláremos de su potencia, fuerte por cierto es; Si de juicio, ¿quién me emplazará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 20, 'Si yo me justificare, me condenará mi boca; Si me dijere perfecto, esto me hará inicuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 21, 'Bien que yo fuese íntegro, no conozco mi alma: Reprocharé mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 22, 'Una cosa resta que yo diga: Al perfecto y al impío él los consume.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 23, 'Si azote mata de presto, Ríese de la prueba de los inocentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 24, 'La tierra es entregada en manos de los impíos, Y él cubre el rostro de sus jueces. Si no es él, ¿quién es? ¿dónde está?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 25, 'Mis días han sido más ligeros que un correo; Huyeron, y no vieron el bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 26, 'Pasaron cual navíos veloces: Como el águila que se arroja á la comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 27, 'Si digo: Olvidaré mi queja, Dejaré mi aburrimiento, y esforzaréme:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 28, 'Contúrbanme todos mis trabajos; Sé que no me darás por libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 29, 'Yo soy impío, ¿Para qué trabajaré en vano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 30, 'Aunque me lave con aguas de nieve, Y limpie mis manos con la misma limpieza,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 31, 'Aun me hundirás en el hoyo, Y mis propios vestidos me abominarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 32, 'Porque no es hombre como yo, para que yo le responda, Y vengamos juntamente á juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 33, 'No hay entre nosotros árbitro Que ponga su mano sobre nosotros ambos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 34, 'Quite de sobre mí su vara, Y su terror no me espante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 9, 35, 'Entonces hablaré, y no le temeré: Porque así no estoy en mí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 1, 'ESTA mi alma aburrida de mi vida: Daré yo suelta á mi queja sobre mí, Hablaré con amargura de mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 2, 'Diré á Dios: no me condenes; Hazme entender por qué pleiteas conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 3, '¿Parécete bien que oprimas, Que deseches la obra de tus manos, Y que resplandezcas sobre el consejo de los impíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 4, '¿Tienes tú ojos de carne? ¿Ves tú como ve el hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 5, '¿Son tus días como los días del hombre, O tus años como los tiempos humanos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 6, 'Para que inquieras mi iniquidad, Y busques mi pecado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 7, 'Sobre saber tú que no soy impío, Y que no hay quien de tu mano libre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 8, 'Tus manos me formaron y me compusieron Todo en contorno: ¿y así me deshaces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 9, 'Acuérdate ahora que como á lodo me diste forma: ¿Y en polvo me has de tornar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 10, '¿No me fundiste como leche, Y como un queso me cuajaste?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 11, 'Vestísteme de piel y carne, Y cubrísteme de huesos y nervios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 12, 'Vida y misericordia me concediste, Y tu visitación guardó mi espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 13, 'Y estas cosas tienes guardadas en tu corazón; Yo sé que esto está cerca de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 14, 'Si pequé, tú me has observado, Y no me limpias de mi iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 15, 'Si fuere malo, ¡ay de mí! Y si fuere justo, no levantaré mi cabeza, Estando harto de deshonra, Y de verme afligido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 16, 'Y subirá de punto, pues me cazas como á león, Y tornas á hacer en mí maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 17, 'Renuevas contra mí tus plagas, Y aumentas conmigo tu furor, Remudándose sobre mí ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 18, '¿Por qué me sacaste de la matriz? Habría yo espirado, y no me vieran ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 19, 'Fuera, como si nunca hubiera sido, Llevado desde el vientre á la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 20, '¿No son mis días poca cosa? Cesa pues, y déjame, para que me conforte un poco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 21, 'Antes que vaya para no volver, A la tierra de tinieblas y de sombra de muerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 10, 22, 'Tierra de oscuridad, lóbrega Como sombra de muerte, sin orden, Y que aparece como la oscuridad misma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 1, 'Y RESPONDIO Sophar Naamathita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 2, '¿Las muchas palabras no han de tener respuesta? ¿Y el hombre parlero será justificado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 3, '¿Harán tus falacias callar á los hombres? ¿Y harás escarnio, y no habrá quien te avergüence?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 4, 'Tú dices: Mi conversar es puro, Y yo soy limpio delante de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 5, 'Mas ¡oh quién diera que Dios hablara, Y abriera sus labios contigo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 6, 'Y que te declarara los arcanos de la sabiduría, Que son de doble valor que la hacienda! Conocerías entonces que Dios te ha castigado menos que tu iniquidad merece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 7, '¿Alcanzarás tú el rastro de Dios? ¿Llegarás tú á la perfección del Todopoderoso?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 8, 'Es más alto que los cielos: ¿qué harás? Es más profundo que el infierno: ¿cómo lo conocerás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 9, 'Su dimensión es más larga que la tierra, Y más ancha que la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 10, 'Si cortare, ó encerrare, O juntare, ¿quién podrá contrarrestarle?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 11, 'Porque él conoce á los hombres vanos: Ve asimismo la iniquidad, ¿y no hará caso?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 12, 'El hombre vano se hará entendido, Aunque nazca como el pollino del asno montés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 13, 'Si tú apercibieres tu corazón, Y extendieres á él tus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 14, 'Si alguna iniquidad hubiere en tu mano, y la echares de ti, Y no consintieres que more maldad en tus habitaciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 15, 'Entonces levantarás tu rostro limpio de mancha, Y serás fuerte y no temerás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 16, 'Y olvidarás tu trabajo, O te acordarás de él como de aguas que pasaron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 17, 'Y en mitad de la siesta se levantará bonanza; Resplandecerás, y serás como la mañana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 18, 'Y confiarás, que habrá esperanza; Y cavarás, y dormirás seguro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 19, 'Y te acostarás, y no habrá quien te espante: Y muchos te rogarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 11, 20, 'Mas los ojos de los malos se consumirán, Y no tendrán refugio; Y su esperanza será agonía del alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 2, 'Ciertamente que vosotros sois el pueblo; Y con vosotros morirá la sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 3, 'También tengo yo seso como vosotros; No soy yo menos que vosotros: ¿Y quién habrá que no pueda decir otro tanto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 4, 'Yo soy uno de quien su amigo se mofa, Que invoca á Dios, y él le responde: Con todo, el justo y perfecto es escarnecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 5, 'Aquel cuyos pies van á resbalar, Es como una lámpara despreciada de aquel que está á sus anchuras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 6, 'Prosperan las tiendas de los ladrones, Y los que provocan á Dios viven seguros; En cuyas manos él ha puesto cuanto tienen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 7, 'Y en efecto, pregunta ahora á las bestias, que ellas te enseñarán; Y á las aves de los cielos, que ellas te lo mostrarán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 8, 'O habla á la tierra, que ella te enseñará; Los peces de la mar te lo declararán también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 9, '¿Qué cosa de todas estas no entiende Que la mano de Jehová la hizo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 10, 'En su mano está el alma de todo viviente, Y el espíritu de toda carne humana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 11, 'Ciertamente el oído distingue las palabras, Y el paladar gusta las viandas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 12, 'En los viejos está la ciencia, Y en la larga edad la inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 13, 'Con Dios está la sabiduría y la fortaleza; Suyo es el consejo y la inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 14, 'He aquí, él derribará, y no será edificado: Encerrará al hombre, y no habrá quien le abra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 15, 'He aquí, el detendrá las aguas, y se secarán; El las enviará, y destruirán la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 16, 'Con él está la fortaleza y la existencia; Suyo es el que yerra, y el que hace errar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 17, 'El hace andar á los consejeros desnudos de consejo, Y hace enloquecer á los jueces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 18, 'El suelta la atadura de los tiranos, Y ata el cinto á sus lomos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 19, 'El lleva despojados á los príncipes, Y trastorna á los poderosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 20, 'El impide el labio á los que dicen verdad, Y quita á los ancianos el consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 21, 'El derrama menosprecio sobre los príncipes, Y enflaquece la fuerza de los esforzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 22, 'El descubre las profundidades de las tinieblas, Y saca á luz la sombra de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 23, 'El multiplica las gentes, y él las destruye: El esparce las gentes, y las torna á recoger.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 24, 'El quita el seso de las cabezas del pueblo de la tierra, Y háceles que se pierdan vagueando sin camino:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 12, 25, 'Van á tientas como en tinieblas y sin luz, Y los hace errar como borrachos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 1, 'HE AQUI que todas estas cosas han visto mis ojos, Y oído y entendido de por sí mis oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 2, 'Como vosotros lo sabéis, lo sé yo; No soy menos que vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 3, 'Mas yo hablaría con el Todopoderoso, Y querría razonar con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 4, 'Que ciertamente vosotros sois fraguadores de mentira; Sois todos vosotros médicos nulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 5, 'Ojalá callarais del todo, Porque os fuera sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 6, 'Oid ahora mi razonamiento, Y estad atentos á los argumentos de mis labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 7, '¿Habéis de hablar iniquidad por Dios? ¿Habéis de hablar por él engaño?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 8, '¿Habéis de hacer acepción de su persona? ¿Habéis de pleitear vosotros por Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 9, '¿Sería bueno que él os escudriñase? ¿Os burlaréis de él como quien se burla de algún hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 10, 'El os reprochará de seguro, Si solapadamente hacéis acepción de personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 11, 'De cierto su alteza os había de espantar, Y su pavor había de caer sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 12, 'Vuestras memorias serán comparadas á la ceniza, Y vuestros cuerpos como cuerpos de lodo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 13, 'Escuchadme, y hablaré yo, Y véngame después lo que viniere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 14, '¿Por qué quitaré yo mi carne con mis dientes, Y pondré mi alma en mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 15, 'He aquí, aunque me matare, en él esperaré; Empero defenderé delante de él mis caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 16, 'Y él mismo me será salud, Porque no entrará en su presencia el hipócrita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 17, 'Oid con atención mi razonamiento, Y mi denunciación con vuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 18, 'He aquí ahora, si yo me apercibiere á juicio, Sé que seré justificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 19, '¿Quién es el que pleiteará conmigo? Porque si ahora yo callara, fenecería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 20, 'A lo menos dos cosas no hagas conmigo; Entonces no me esconderé de tu rostro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 21, 'Aparta de mí tu mano, Y no me asombre tu terror.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 22, 'Llama luego, y yo responderé; O yo hablaré, y respóndeme tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 23, '¿Cuántas iniquidades y pecados tengo yo? Hazme entender mi prevaricación y mi pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 24, '¿Por qué escondes tu rostro, Y me cuentas por tu enemigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 25, '¿A la hoja arrebatada has de quebrantar? ¿Y á una arista seca has de perseguir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 26, '¿Por qué escribes contra mí amarguras, Y me haces cargo de los pecados de mi mocedad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 27, 'Pones además mis pies en el cepo, y guardas todos mis caminos, Imprimiéndolo á las raíces de mis pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 13, 28, 'Y el cuerpo mío se va gastando como de carcoma, Como vestido que se come de polilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 1, 'EL HOMBRE nacido de mujer, Corto de días, y harto de sinsabores:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 2, 'Que sale como una flor y es cortado; Y huye como la sombra, y no permanece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 3, '¿Y sobre éste abres tus ojos, Y me traes á juicio contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 4, '¿Quién hará limpio de inmundo? Nadie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 5, 'Ciertamente sus días están determinados, y el número de sus meses está cerca de ti: Tú le pusiste términos, de los cuales no pasará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 6, 'Si tú lo dejares, él dejará de ser: Entre tanto deseará, como el jornalero, su día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 7, 'Porque si el árbol fuere cortado, aún queda de él esperanza; retoñecerá aún, Y sus renuevos no faltarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 8, 'Si se envejeciere en la tierra su raíz, Y su tronco fuere muerto en el polvo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 9, 'Al percibir el agua reverdecerá, Y hará copa como planta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 10, 'Mas el hombre morirá, y será cortado; Y perecerá el hombre, ¿y dónde estará él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 11, 'Las aguas de la mar se fueron, Y agotóse el río, secóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 12, 'Así el hombre yace, y no se tornará á levantar: Hasta que no haya cielo no despertarán, Ni se levantarán de su sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 13, '¡Oh quién me diera que me escondieses en el sepulcro, Que me encubrieras hasta apaciguarse tu ira, Que me pusieses plazo, y de mí te acordaras!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 14, 'Si el hombre muriere, ¿volverá á vivir? Todos los días de mi edad esperaré, Hasta que venga mi mutación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 15, 'Aficionado á la obra de tus manos, Llamarás, y yo te responderé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 16, 'Pues ahora me cuentas los pasos, Y no das tregua á mi pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 17, 'Tienes sellada en saco mi prevaricación, Y coacervas mi iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 18, 'Y ciertamente el monte que cae se deshace, Y las peñas son traspasadas de su lugar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 19, 'Las piedras son desgastadas con el agua impetuosa, Que se lleva el polvo de la tierra: de tal manera haces tú perecer la esperanza del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 20, 'Para siempre serás más fuerte que él, y él se va; Demudarás su rostro, y enviaráslo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 21, 'Sus hijos serán honrados, y él no lo sabrá; O serán humillados, y no entenderá de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 14, 22, 'Mas su carne sobre él se dolerá, Y entristecerse ha en él su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 1, 'Y RESPONDIO Eliphaz Temanita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 2, '¿Si proferirá el sabio vana sabiduría, Y henchirá su vientre de viento solano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 3, '¿Disputará con palabras inútiles, Y con razones sin provecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 4, 'Tú también disipas el temor, Y menoscabas la oración delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 5, 'Porque tu boca declaró tu iniquidad, Pues has escogido el hablar de los astutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 6, 'Tu boca te condenará, y no yo; Y tus labios testificarán contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 7, '¿Naciste tú primero que Adam? ¿O fuiste formado antes que los collados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 8, '¿Oíste tú el secreto de Dios, Que detienes en ti solo la sabiduría?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 9, '¿Qué sabes tú que no sepamos? ¿Qué entiendes que no se halle en nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 10, 'Entre nosotros también hay cano, también hay viejo Mucho mayor en días que tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 11, '¿En tan poco tienes las consolaciones de Dios? ¿Tienes acaso alguna cosa oculta cerca de ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 12, '¿Por qué te enajena tu corazón, Y por qué guiñan tus ojos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 13, 'Pues haces frente á Dios con tu espíritu, Y sacas tales palabras de tu boca?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 14, '¿Qué cosa es el hombre para que sea limpio, Y que se justifique el nacido de mujer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 15, 'He aquí que en sus santos no confía, Y ni los cielos son limpios delante de sus ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 16, '¿Cuánto menos el hombre abominable y vil, Que bebe la iniquidad como agua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 17, 'Escúchame; yo te mostraré Y te contaré lo que he visto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 18, '(Lo que los sabios nos contaron De sus padres, y no lo encubrieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 19, 'A los cuales solos fué dada la tierra, Y no pasó extraño por medio de ellos:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 20, 'Todos los días del impío, él es atormentado de dolor, Y el número de años es escondido al violento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 21, 'Estruendos espantosos hay en sus oídos; En la paz le vendrá quien lo asuele.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 22, 'El no creerá que ha de volver de las tinieblas, Y está mirando al cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 23, 'Desasosegado á comer siempre, Sabe que le está aparejado día de tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 24, 'Tribulación y angustia le asombrarán, Y esforzaránse contra él como un rey apercibido para la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 25, 'Por cuanto él extendió su mano contra Dios, Y se esforzó contra el Todopoderoso,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 26, 'El le acometerá en la cerviz, En lo grueso de las hombreras de sus escudos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 27, 'Porque cubrió su rostro con su gordura, E hizo pliegues sobre los ijares;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 28, 'Y habitó las ciudades asoladas, Las casas inhabitadas, Que estaban puestas en montones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 29, 'No enriquecerá, ni será firme su potencia, Ni extenderá por la tierra su hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 30, 'No se escapará de las tinieblas: La llama secará sus ramos, Y con el aliento de su boca perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 31, 'No confíe el iluso en la vanidad; Porque ella será su recompensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 32, 'El será cortado antes de su tiempo, Y sus renuevos no reverdecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 33, 'El perderá su agraz como la vid, Y derramará su flor como la oliva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 34, 'Porque la sociedad de los hipócritas será asolada, Y fuego consumirá las tiendas de soborno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 15, 35, 'Concibieron dolor, y parieron iniquidad; Y las entradas de ellos meditan engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 2, 'Muchas veces he oído cosas como estas: Consoladores molestos sois todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 3, '¿Tendrán fin las palabras ventosas? O ¿qué te animará á responder?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 4, 'También yo hablaría como vosotros. Ojalá vuestra alma estuviera en lugar de la mía, Que yo os tendría compañía en las palabras, Y sobre vosotros movería mi cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 5, 'Mas yo os alentaría con mis palabras, Y la consolación de mis labios apaciguaría el dolor vuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 6, 'Si hablo, mi dolor no cesa; Y si dejo de hablar, no se aparta de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 7, 'Empero ahora me ha fatigado: Has tú asolado toda mi compañía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 8, 'Tú me has arrugado; testigo es mi flacura, Que se levanta contra mí para testificar en mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 9, 'Su furor me destrizó, y me ha sido contrario: Crujió sus dientes contra mí; Contra mí aguzó sus ojos mi enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 10, 'Abrieron contra mí su boca; Hirieron mis mejillas con afrenta; Contra mí se juntaron todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 11, 'Hame entregado Dios al mentiroso, Y en las manos de los impíos me hizo estremecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 12, 'Próspero estaba, y desmenuzóme: Y arrebatóme por la cerviz, y despedazóme, Y púsome por blanco suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 13, 'Cercáronme sus flecheros, Partió mis riñones, y no perdonó: Mi hiel derramó por tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 14, 'Quebrantóme de quebranto sobre quebranto; Corrió contra mí como un gigante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 15, 'Yo cosí saco sobre mi piel, Y cargué mi cabeza de polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 16, 'Mi rostro está enlodado con lloro, Y mis párpados entenebrecidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 17, 'A pesar de no haber iniquidad en mis manos, Y de haber sido mi oración pura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 18, '¡Oh tierra! no cubras mi sangre, Y no haya lugar á mi clamor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 19, 'Mas he aquí que en los cielos está mi testigo, Y mi testimonio en las alturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 20, 'Disputadores son mis amigos: Mas á Dios destilarán mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 21, '¡Ojalá pudiese disputar el hombre con Dios, Como con su prójimo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 16, 22, 'Mas los años contados vendrán, Y yo iré el camino por donde no volveré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 1, 'MI ALIENTO está corrompido, acórtanse mis días, Y me está aparejado el sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 2, 'No hay conmigo sino escarnecedores, En cuya acrimonia se detienen mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 3, 'Pon ahora, dame fianza para litigar contigo: ¿Quién tocará ahora mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 4, 'Porque á éstos has tú escondido su corazón de inteligencia: Por tanto, no los ensalzarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 5, 'El que denuncia lisonjas á sus prójimos, Los ojos de sus hijos desfallezcan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 6, 'El me ha puesto por parábola de pueblos, Y delante de ellos he sido como tamboril.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 7, 'Y mis ojos se oscurecieron de desabrimiento, Y mis pensamientos todos son como sombra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 8, 'Los rectos se maravillarán de esto, Y el inocente se levantará contra el hipócrita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 9, 'No obstante, proseguirá el justo su camino, Y el limpio de manos aumentará la fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 10, 'Mas volved todos vosotros, y venid ahora, Que no hallaré entre vosotros sabio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 11, 'Pasáronse mis días, fueron arrancados mis pensamientos, Los designios de mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 12, 'Pusieron la noche por día, Y la luz se acorta delante de las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 13, 'Si yo espero, el sepulcro es mi casa: Haré mi cama en las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 14, 'A la huesa tengo dicho: Mi padre eres tú; A los gusanos: Mi madre y mi hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 15, '¿Dónde pues estará ahora mi esperanza? Y mi esperanza ¿quién la verá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 17, 16, 'A los rincones de la huesa descenderán, Y juntamente descansarán en el polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 1, 'Y RESPONDIO Bildad Suhita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 2, '¿Cuándo pondréis fin á las palabras? Entended, y después hablemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 3, '¿Por qué somos tenidos por bestias, Y en vuestros ojos somos viles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 4, 'Oh tú, que despedazas tu alma con tu furor, ¿Será dejada la tierra por tu causa, Y serán traspasadas de su lugar las peñas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 5, 'Ciertamente la luz de los impíos será apagada, Y no resplandecerá la centella de su fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 6, 'La luz se oscurecerá en su tienda, Y apagaráse sobre él su lámpara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 7, 'Los pasos de su pujanza serán acortados, Y precipitarálo su mismo consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 8, 'Porque red será echada en sus pies, Y sobre red andará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 9, 'Lazo prenderá su calcañar: Afirmaráse la trampa contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 10, 'Su cuerda está escondida en la tierra, Y su torzuelo sobre la senda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 11, 'De todas partes lo asombrarán temores, Y haránle huir desconcertado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 12, 'Su fuerza será hambrienta, Y á su lado estará aparejado quebrantamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 13, 'El primogénito de la muerte comerá los ramos de su piel, Y devorará sus miembros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 14, 'Su confianza será arrancada de su tienda, Y harále esto llevar al rey de los espantos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 15, 'En su tienda morará como si no fuese suya: Piedra azufre será esparcida sobre su morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 16, 'Abajo se secarán sus raíces, Y arriba serán cortadas sus ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 17, 'Su memoria perecerá de la tierra, Y no tendrá nombre por las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 18, 'De la luz será lanzado á las tinieblas, Y echado fuera del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 19, 'No tendrá hijo ni nieto en su pueblo, Ni quien le suceda en sus moradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 20, 'Sobre su día se espantarán los por venir, Como ocupó el pavor á los que fueron antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 18, 21, 'Ciertamente tales son las moradas del impío, Y este será el lugar del que no conoció á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 2, '¿Hasta cuándo angustiaréis mi alma, Y me moleréis con palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 3, 'Ya me habéis vituperado diez veces: ¿No os avergonzáis de descomediros delante de mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 4, 'Sea así que realmente haya yo errado, Conmigo se quedará mi yerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 5, 'Mas si vosotros os engrandeciereis contra mí, Y adujereis contra mí mi oprobio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 6, 'Sabed ahora que Dios me ha trastornado, Y traído en derredor su red sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 7, 'He aquí yo clamaré agravio, y no seré oído: Daré voces, y no habrá juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 8, 'Cercó de vallado mi camino, y no pasaré; Y sobre mis veredas puso tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 9, 'Hame despojado de mi gloria, Y quitado la corona de mi cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 10, 'Arruinóme por todos lados, y perezco; Y ha hecho pasar mi esperanza como árbol arrancado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 11, 'E hizo inflamar contra mí su furor, Y contóme para sí entre sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 12, 'Vinieron sus ejércitos á una, y trillaron sobre mí su camino, Y asentaron campo en derredor de mi tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 13, 'Hizo alejar de mí mis hermanos, Y positivamente se extrañaron de mí mis conocidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 14, 'Mis parientes se detuvieron, Y mis conocidos se olvidaron de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 15, 'Los moradores de mi casa y mis criadas me tuvieron por extraño; Forastero fuí yo en sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 16, 'Llamé á mi siervo, y no respondió; De mi propia boca le suplicaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 17, 'Mi aliento vino á ser extraño á mi mujer, Aunque por los hijos de mis entrañas le rogaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 18, 'Aun los muchachos me menospreciaron: En levantándome, hablaban contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 19, 'Todos mis confidentes me aborrecieron; Y los que yo amaba, se tornaron contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 20, 'Mi cuero y mi carne se pegaron á mis huesos; Y he escapado con la piel de mis dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 21, 'Oh vosotros mis amigos, tened compasión de mí, tened compasión de mí; Porque la mano de Dios me ha tocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 22, '¿Por qué me perseguís como Dios, Y no os hartáis de mis carnes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 23, '¡Quién diese ahora que mis palabras fuesen escritas! ¡Quién diese que se escribieran en un libro!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 24, '¡Que con cincel de hierro y con plomo Fuesen en piedra esculpidas para siempre!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 25, 'Yo sé que mi Redentor vive, Y al fin se levantará sobre el polvo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 26, 'Y después de deshecha esta mi piel, Aun he de ver en mi carne á Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 27, 'Al cual yo tengo de ver por mí, Y mis ojos lo verán, y no otro, Aunque mis riñones se consuman dentro de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 28, 'Mas debierais decir: ¿Por qué lo perseguimos? Ya que la raíz del negocio en mí se halla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 19, 29, 'Temed vosotros delante de la espada; Porque sobreviene el furor de la espada á causa de las injusticias, Para que sepáis que hay un juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 1, 'Y RESPONDIO Sophar Naamathita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 2, 'Por cierto mis pensamientos me hacen responder, Y por tanto me apresuro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 3, 'La reprensión de mi censura he oído, Y háceme responder el espíritu de mi inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 4, '¿No sabes esto que fué siempre, Desde el tiempo que fué puesto el hombre sobre la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 5, 'Que la alegría de los impíos es breve, Y el gozo del hipócrita por un momento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 6, 'Si subiere su altivez hasta el cielo, Y su cabeza tocare en las nubes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 7, 'Con su estiércol perecerá para siempre: Los que le hubieren visto, dirán: ¿Qué es de él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 8, 'Como sueño volará, y no será hallado: Y disiparáse como visión nocturna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 9, 'El ojo que le habrá visto, nunca más le verá; Ni su lugar le echará más de ver.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 10, 'Sus hijos pobres andarán rogando; Y sus manos tornarán lo que él robó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 11, 'Sus huesos están llenos de sus mocedades, Y con él serán sepultados en el polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 12, 'Si el mal se endulzó en su boca, Si lo ocultaba debajo de su lengua;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 13, 'Si le parecía bien, y no lo dejaba, Mas antes lo detenía entre su paladar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 14, 'Su comida se mudará en sus entrañas, Hiel de áspides será dentro de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 15, 'Devoró riquezas, mas vomitarálas; De su vientre las sacará Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 16, 'Veneno de áspides chupará; Matarálo lengua de víbora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 17, 'No verá los arroyos, los ríos, Los torrentes de miel y de manteca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 18, 'Restituirá el trabajo conforme á la hacienda que tomó; Y no tragará, ni gozará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 19, 'Por cuanto quebrantó y desamparó á los pobres, Robó casas, y no las edificó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 20, 'Por tanto, no sentirá él sosiego en su vientre, Ni salvará nada de lo que codiciaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 21, 'No quedó nada que no comiese: Por tanto su bien no será durable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 22, 'Cuando fuere lleno su bastimento, tendrá angustia: Las manos todas de los malvados vendrán sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 23, 'Cuando se pusiere á henchir su vientre, Dios enviará sobre él el furor de su ira, Y harála llover sobre él y sobre su comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 24, 'Huirá de las armas de hierro, Y el arco de acero le atravesará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 25, 'Desenvainará y sacará saeta de su aljaba, Y relumbrante pasará por su hiel: Sobre él vendrán terrores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 26, 'Todas tinieblas están guardadas para sus secretos: Fuego no soplado lo devorará; Su sucesor será quebrantado en su tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 27, 'Los cielos descubrirán su iniquidad, Y la tierra se levantará contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 28, 'Los renuevos de su casa serán trasportados; Serán derramados en el día de su furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 20, 29, 'Esta es la parte que Dios apareja al hombre impío, Y la heredad que Dios le señala por su palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 2, 'Oid atentamente mi palabra, Y sea esto vuestros consuelos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 3, 'Soportadme, y yo hablaré; Y después que hubiere hablado, escarneced.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 4, '¿Hablo yo á algún hombre? Y ¿por qué no se ha de angustiar mi espíritu?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 5, 'Miradme, y espantaos, Y poned la mano sobre la boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 6, 'Aun yo mismo, cuando me acuerdo, me asombro, Y toma temblor mi carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 7, '¿Por qué viven los impíos, Y se envejecen, y aun crecen en riquezas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 8, 'Su simiente con ellos, compuesta delante de ellos; Y sus renuevos delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 9, 'Sus casas seguras de temor, Ni hay azote de Dios sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 10, 'Sus vacas conciben, no abortan; Paren sus vacas, y no malogran su cría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 11, 'Salen sus chiquitos como manada, Y sus hijos andan saltando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 12, 'Al son de tamboril y cítara saltan, Y se huelgan al son del órgano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 13, 'Gastan sus días en bien, Y en un momento descienden á la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 14, 'Dicen pues á Dios: Apártate de nosotros, Que no queremos el conocimiento de tus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 15, '¿Quién es el Todopoderoso, para que le sirvamos? ¿Y de qué nos aprovechará que oremos á él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 16, 'He aquí que su bien no está en manos de ellos: El consejo de los impíos lejos esté de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 17, '¡Oh cuántas veces la lámpara de los impíos es apagada, Y viene sobre ellos su quebranto, Y Dios en su ira les reparte dolores!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 18, 'Serán como la paja delante del viento, Y como el tamo que arrebata el torbellino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 19, 'Dios guardará para sus hijos su violencia; Y le dará su pago, para que conozca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 20, 'Verán sus ojos su quebranto, Y beberá de la ira del Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 21, 'Porque ¿qué deleite tendrá él de su casa después de sí, Siendo cortado el número de sus meses?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 22, '¿Enseñará alguien á Dios sabiduría, Juzgando él á los que están elevados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 23, 'Este morirá en el vigor de su hermosura, todo quieto y pacífico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 24, 'Sus colodras están llenas de leche, Y sus huesos serán regados de tuétano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 25, 'Y estotro morirá en amargura de ánimo, Y no habiendo comido jamás con gusto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 26, 'Igualmente yacerán ellos en el polvo, Y gusanos los cubrirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 27, 'He aquí, yo conozco vuestros pensamientos, Y las imaginaciones que contra mí forjáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 28, 'Porque decís: ¿Qué es de la casa del príncipe, Y qué de la tienda de las moradas de los impíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 29, '¿No habéis preguntado á los que pasan por los caminos, Por cuyas señas no negaréis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 30, 'Que el malo es reservado para el día de la destrucción? Presentados serán en el día de las iras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 31, '¿Quién le denunciará en su cara su camino? Y de lo que él hizo, ¿quién le dará el pago?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 32, 'Porque llevado será él á los sepulcros, Y en el montón permanecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 33, 'Los terrones del valle le serán dulces; Y tras de él será llevado todo hombre, Y antes de él han ido innumerables.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 21, 34, '¿Cómo pues me consoláis en vano, Viniendo á parar vuestras respuestas en falacia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 1, 'Y RESPONDIO Eliphaz Temanita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 2, '¿Traerá el hombre provecho á Dios, Porque el sabio sea provechoso á sí mismo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 3, '¿Tiene su contentamiento el Omnipotente en que tú seas justificado, O provecho de que tú hagas perfectos tus caminos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 4, '¿Castigaráte acaso, O vendrá contigo á juicio porque te teme?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 5, 'Por cierto tu malicia es grande, Y tus maldades no tienen fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 6, 'Porque sacaste prenda á tus hermanos sin causa, E hiciste desnudar las ropas de los desnudos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 7, 'No diste de beber agua al cansado, Y detuviste el pan al hambriento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 8, 'Empero el hombre pudiente tuvo la tierra; Y habitó en ella el distinguido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 9, 'Las viudas enviaste vacías, Y los brazos de los huérfanos fueron quebrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 10, 'Por tanto hay lazos alrededor de ti, Y te turba espanto repentino;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 11, 'O tinieblas, porque no veas; Y abundancia de agua te cubre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 12, '¿No está Dios en la altura de los cielos? Mira lo encumbrado de las estrellas, cuán elevadas están.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 13, '¿Y dirás tú: Qué sabe Dios? ¿Cómo juzgará por medio de la oscuridad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 14, 'Las nubes son su escondedero, y no ve; Y por el circuito del cielo se pasea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 15, '¿Quieres tú guardar la senda antigua, Que pisaron los hombres perversos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 16, 'Los cuales fueron cortados antes de tiempo, Cuyo fundamento fué como un río derramado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 17, 'Que decían á Dios: Apártate de nosotros. ¿Y qué les había hecho el Omnipotente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 18, 'Habíales él henchido sus casas de bienes. Sea empero el consejo de ellos lejos de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 19, 'Verán los justos y se gozarán; Y el inocente los escarnecerá, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 20, 'Fué cortada nuestra sustancia, Habiendo consumido el fuego el resto de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 21, 'Amístate ahora con él, y tendrás paz; Y por ello te vendrá bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 22, 'Toma ahora la ley de su boca, Y pon sus palabras en tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 23, 'Si te tornares al Omnipotente, serás edificado; Alejarás de tu tienda la aflicción;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 24, 'Y tendrás más oro que tierra, Y como piedras de arroyos oro de Ophir;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 25, 'Y el Todopoderoso será tu defensa, Y tendrás plata á montones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 26, 'Porque entonces te deleitarás en el Omnipotente, Y alzarás á Dios tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 27, 'Orarás á él, y él te oirá; Y tú pagarás tus votos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 28, 'Determinarás asimismo una cosa, y serte ha firme; Y sobre tus caminos resplandecerá luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 29, 'Cuando fueren abatidos, dirás tú: Ensalzamiento habrá: Y Dios salvará al humilde de ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 22, 30, 'El libertará la isla del inocente; Y por la limpieza de tus manos será librada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 2, 'Hoy también hablaré con amargura; Que es más grave mi llaga que mi gemido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 3, '¡Quién me diera el saber dónde hallar á Dios! Yo iría hasta su silla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 4, 'Ordenaría juicio delante de él, Y henchiría mi boca de argumentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 5, 'Yo sabría lo que él me respondería, Y entendería lo que me dijese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 6, '¿Pleitearía conmigo con grandeza de fuerza? No: antes él la pondría en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 7, 'Allí el justo razonaría con él: Y escaparía para siempre de mi juez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 8, 'He aquí yo iré al oriente, y no lo hallaré; Y al occidente, y no lo percibiré:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 9, 'Si al norte él obrare, yo no lo veré; Al mediodía se esconderá, y no lo veré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 10, 'Mas él conoció mi camino: Probaráme, y saldré como oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 11, 'Mis pies tomaron su rastro; Guardé su camino, y no me aparté.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 12, 'Del mandamiento de sus labios nunca me separé; Guardé las palabras de su boca más que mi comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 13, 'Empero si él se determina en una cosa, ¿quién lo apartará? Su alma deseó, é hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 14, 'El pues acabará lo que ha determinado de mí: Y muchas cosas como estas hay en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 15, 'Por lo cual yo me espanto en su presencia: Consideraré, y temerélo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 16, 'Dios ha enervado mi corazón, Y hame turbado el Omnipotente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 23, 17, '¿Por qué no fuí yo cortado delante de las tinieblas, Y cubrió con oscuridad mi rostro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 1, 'PUESTO que no son ocultos los tiempos al Todopoderoso, ¿Por qué los que le conocen no ven sus días?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 2, 'Traspasan los términos, Roban los ganados, y apaciéntanlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 3, 'Llévanse el asno de los huérfanos; Prenden el buey de la viuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 4, 'Hacen apartar del camino á los menesterosos: Y todos los pobres de la tierra se esconden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 5, 'He aquí, como asnos monteses en el desierto, Salen á su obra madrugando para robar; El desierto es mantenimiento de sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 6, 'En el campo siegan su pasto, Y los impíos vendimian la viña ajena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 7, 'Al desnudo hacen dormir sin ropa, Y que en el frío no tenga cobertura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 8, 'Con las avenidas de los montes se mojan, Y abrazan las peñas sin tener abrigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 9, 'Quitan el pecho á los huérfanos, Y de sobre el pobre toman la prenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 10, 'Al desnudo hacen andar sin vestido, Y á los hambrientos quitan los hacecillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 11, 'De dentro de sus paredes exprimen el aceite, Pisan los lagares, y mueren de sed.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 12, 'De la ciudad gimen los hombres, Y claman las almas de los heridos de muerte: Mas Dios no puso estorbo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 13, 'Ellos son los que, rebeldes á la luz, Nunca conocieron sus caminos, Ni estuvieron en sus veredas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 14, 'A la luz se levanta el matador, mata al pobre y al necesitado, Y de noche es como ladrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 15, 'El ojo del adúltero está aguardando la noche, Diciendo: No me verá nadie: Y esconde su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 16, 'En las tinieblas minan las casas, Que de día para sí señalaron; No conocen la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 17, 'Porque la mañana es á todos ellos como sombra de muerte; Si son conocidos, terrores de sombra de muerte los toman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 18, 'Son instables más que la superficie de las aguas; Su porción es maldita en la tierra; No andarán por el camino de las viñas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 19, 'La sequía y el calor arrebatan las aguas de la nieve; Y el sepulcro á los pecadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 20, 'Olvidaráse de ellos el seno materno; de ellos sentirán los gusanos dulzura; Nunca más habrá de ellos memoria, Y como un árbol serán los impíos quebrantados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 21, 'A la mujer estéril que no paría, afligió; Y á la viuda nunca hizo bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 22, 'Mas á los fuertes adelantó con su poder: Levantóse, y no se da por segura la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 23, 'Le dieron á crédito, y se afirmó: Sus ojos están sobre los caminos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 24, 'Fueron ensalzados por un poco, mas desaparecen, Y son abatidos como cada cual: serán encerrados, Y cortados como cabezas de espigas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 24, 25, 'Y si no, ¿quién me desmentirá ahora, O reducirá á nada mis palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 25, 1, 'Y RESPONDIO Bildad Suhita, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 25, 2, 'El señorío y el temor están con él: El hace paz en sus alturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 25, 3, '¿Tienen sus ejércitos número? ¿Y sobre quién no está su luz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 25, 4, '¿Cómo pues se justificará el hombre con Dios? ¿Y cómo será limpio el que nace de mujer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 25, 5, 'He aquí que ni aun la misma luna será resplandeciente, Ni las estrellas son limpias delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 25, 6, '¿Cuánto menos el hombre que es un gusano, Y el hijo de hombre, también gusano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 1, 'Y RESPONDIO Job, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 2, '¿En qué ayudaste al que no tiene fuerza? ¿Has amparado al brazo sin fortaleza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 3, '¿En qué aconsejaste al que no tiene ciencia, Y mostraste bien sabiduría?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 4, '¿A quién has anunciado palabras, Y cuyo es el espíritu que de ti sale?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 5, 'Cosas inanimadas son formadas Debajo de las aguas, y los habitantes de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 6, 'El sepulcro es descubierto delante de él, Y el infierno no tiene cobertura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 7, 'Extiende el alquilón sobre vacío, Cuelga la tierra sobre nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 8, 'Ata las aguas en sus nubes, Y las nubes no se rompen debajo de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 9, 'El restriñe la faz de su trono, Y sobre él extiende su nube.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 10, 'El cercó con término la superficie de las aguas, Hasta el fin de la luz y las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 11, 'Las columnas del cielo tiemblan, Y se espantan de su reprensión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 12, 'El rompe la mar con su poder, Y con su entendimiento hiere la hinchazón suya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 13, 'Su espíritu adornó los cielos; Su mano crió la serpiente tortuosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 26, 14, 'He aquí, estas son partes de sus caminos: ¡Mas cuán poco hemos oído de él! Porque el estruendo de sus fortalezas, ¿quién lo detendrá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 1, 'Y REASUMIO Job su discurso, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 2, 'Vive Dios, el cual ha apartado mi causa, Y el Omnipotente, que amargó el alma mía,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 3, 'Que todo el tiempo que mi alma estuviere en mí, Y hubiere hálito de Dios en mis narices,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 4, 'Mis labios no hablarán iniquidad, Ni mi lengua pronunciará engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 5, 'Nunca tal acontezca que yo os justifique: Hasta morir no quitaré de mí mi integridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 6, 'Mi justicia tengo asida, y no la cederé: No me reprochará mi corazón en el tiempo de mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 7, 'Sea como el impío mi enemigo, Y como el inicuo mi adversario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 8, 'Porque ¿cuál es la esperanza del hipócrita, por mucho que hubiere robado, Cuando Dios arrebatare su alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 9, '¿Oirá Dios su clamor Cuando la tribulación sobre él viniere?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 10, '¿Deleitaráse en el Omnipotente? ¿Invocará á Dios en todo tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 11, 'Yo os enseñaré en orden á la mano de Dios: No esconderé lo que hay para con el Omnipotente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 12, 'He aquí que todos vosotros lo habéis visto: ¿Por qué pues os desvanecéis con fantasía?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 13, 'Esta es para con Dios la suerte del hombre impío, Y la herencia que los violentos han de recibir del Omnipotente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 14, 'Si sus hijos fueren multiplicados, serán para el cuchillo; Y sus pequeños no se hartarán de pan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 15, 'Los que le quedaren, en muerte serán sepultados; Y no llorarán sus viudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 16, 'Si amontonare plata como polvo, Y si preparare ropa como lodo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 17, 'Habrála él preparado, mas el justo se vestirá, Y el inocente repartirá la plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 18, 'Edificó su casa como la polilla, Y cual cabaña que el guarda hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 19, 'El rico dormirá, mas no será recogido: Abrirá sus ojos, mas él no será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 20, 'Asirán de él terrores como aguas: Torbellino lo arrebatará de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 21, 'Lo antecogerá el solano, y partirá; Y tempestad lo arrebatará del lugar suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 22, 'Dios pues descargará sobre él, y no perdonará: Hará él por huir de su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 27, 23, 'Batirán sus manos sobre él, Y desde su lugar le silbarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 1, 'CIERTAMENTE la plata tiene sus veneros, Y el oro lugar donde se forma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 2, 'El hierro se saca del polvo, Y de la piedra es fundido el metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 3, 'A las tinieblas puso término, Y examina todo á la perfección, Las piedras que hay en la oscuridad y en la sombra de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 4, 'Brota el torrente de junto al morador, Aguas que el pie había olvidado: Sécanse luego, vanse del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 5, 'De la tierra nace el pan, Y debajo de ella estará como convertida en fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 6, 'Lugar hay cuyas piedras son zafiro, Y sus polvos de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 7, 'Senda que nunca la conoció ave, Ni ojo de buitre la vió:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 8, 'Nunca la pisaron animales fieros, Ni león pasó por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 9, 'En el pedernal puso su mano, Y trastornó los montes de raíz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 10, 'De los peñascos cortó ríos, Y sus ojos vieron todo lo preciado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 11, 'Detuvo los ríos en su nacimiento, E hizo salir á luz lo escondido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 12, 'Empero ¿dónde se hallará la sabiduría? ¿Y dónde está el lugar de la prudencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 13, 'No conoce su valor el hombre, Ni se halla en la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 14, 'El abismo dice: No está en mí: Y la mar dijo: Ni conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 15, 'No se dará por oro, Ni su precio será á peso de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 16, 'No puede ser apreciada con oro de Ophir, Ni con onique precioso, ni con zafiro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 17, 'El oro no se le igualará, ni el diamante; Ni se trocará por vaso de oro fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 18, 'De coral ni de perlas no se hará mención: La sabiduría es mejor que piedras preciosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 19, 'No se igualará con ella esmeralda de Ethiopía; No se podrá apreciar con oro fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 20, '¿De dónde pues vendrá la sabiduría? ¿Y dónde está el lugar de la inteligencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 21, 'Porque encubierta está á los ojos de todo viviente, y á toda ave del cielo es oculta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 22, 'El infierno y la muerte dijeron: Su fama hemos oído con nuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 23, 'Dios entiende el camino de ella, Y él conoce su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 24, 'Porque él mira hasta los fines de la tierra, Y ve debajo de todo el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 25, 'Al dar peso al viento, Y poner las aguas por medida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 26, 'Cuando él hizo ley á la lluvia, Y camino al relámpago de los truenos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 27, 'Entonces la veía él, y la manifestaba: Preparóla y descubrióla también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 28, 28, 'Y dijo al hombre: He aquí que el temor del Señor es la sabiduría, Y el apartarse del mal la inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 1, 'Y VOLVIO Job á tomar su propósito, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 2, '¡Quién me tornase como en los meses pasados, Como en los días que Dios me guardaba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 3, 'Cuando hacía resplandecer su candela sobre mi cabeza, A la luz de la cual yo caminaba en la oscuridad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 4, 'Como fué en los días de mi mocedad, Cuando el secreto de Dios estaba en mi tienda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 5, 'Cuando aún el Omnipotente estaba conmigo, Y mis hijos alrededor de mi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 6, 'Cuando lavaba yo mis caminos con manteca, Y la piedra me derramaba ríos de aceite!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 7, 'Cuando salía á la puerta á juicio, Y en la plaza hacía preparar mi asiento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 8, 'Los mozos me veían, y se escondían; Y los viejos se levantaban, y estaban en pie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 9, 'Los príncipes detenían sus palabras, Ponían la mano sobre su boca;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 10, 'La voz de los principales se ocultaba, Y su lengua se pegaba á su paladar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 11, 'Cuando los oídos que me oían, me llamaban bienaventurado, Y los ojos que me veían, me daban testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 12, 'Porque libraba al pobre que gritaba, Y al huérfano que carecía de ayudador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 13, 'La bendición del que se iba á perder venía sobre mí; Y al corazón de la viuda daba alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 14, 'Vestíame de justicia, y ella me vestía como un manto; Y mi toca era juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 15, 'Yo era ojos al ciego, Y pies al cojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 16, 'A los menesterosos era padre; Y de la causa que no entendía, me informaba con diligencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 17, 'Y quebraba los colmillos del inicuo, Y de sus dientes hacía soltar la presa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 18, 'Y decía yo: En mi nido moriré, Y como arena multiplicaré días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 19, 'Mi raíz estaba abierta junto á las aguas, Y en mis ramas permanecía el rocío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 20, 'Mi honra se renovaba en mí, Y mi arco se corroboraba en mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 21, 'Oíanme, y esperaban; Y callaban á mi consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 22, 'Tras mi palabra no replicaban, Y mi razón destilaba sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 23, 'Y esperábanme como á la lluvia, Y abrían su boca como á la lluvia tardía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 24, 'Si me reía con ellos, no lo creían: Y no abatían la luz de mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 29, 25, 'Calificaba yo el camino de ellos, y sentábame en cabecera; Y moraba como rey en el ejército, Como el que consuela llorosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 1, 'MAS ahora los más mozos de días que yo, se ríen de mí; Cuyos padres yo desdeñara ponerlos con los perros de mi ganado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 2, 'Porque ¿para qué yo habría menester la fuerza de sus manos, En los cuales había perecido con el tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 3, 'Por causa de la pobreza y del hambre andaban solos; Huían á la soledad, á lugar tenebroso, asolado y desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 4, 'Que cogían malvas entre los arbustos, Y raíces de enebro para calentarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 5, 'Eran echados de entre las gentes, Y todos les daban grita como al ladrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 6, 'Habitaban en las barrancas de los arroyos, En las cavernas de la tierra, y en las rocas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 7, 'Bramaban entre las matas, Y se reunían debajo de las espinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 8, 'Hijos de viles, y hombres sin nombre, Más bajos que la misma tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 9, 'Y ahora yo soy su canción, Y he sido hecho su refrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 10, 'Abomínanme, aléjanse de mí, Y aun de mi rostro no detuvieron su saliva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 11, 'Porque Dios desató mi cuerda, y me afligió, Por eso se desenfrenaron delante de mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 12, 'A la mano derecha se levantaron los jóvenes; Empujaron mis pies, Y sentaron contra mí las vías de su ruina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 13, 'Mi senda desbarataron, Aprovecháronse de mi quebrantamiento, Contra los cuales no hubo ayudador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 14, 'Vinieron como por portillo ancho, Revolviéronse á mi calamidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 15, 'Hanse revuelto turbaciones sobre mí; Combatieron como viento mi alma, Y mi salud pasó como nube');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 16, 'Y ahora mi alma está derramada en mí; Días de aflicción me han aprehendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 17, 'De noche taladra sobre mí mis huesos, Y mis pulsos no reposan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 18, 'Con la grande copia de materia mi vestidura está demudada; Cíñeme como el cuello de mi túnica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 19, 'Derribóme en el lodo, Y soy semejante al polvo y á la ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 20, 'Clamo á ti, y no me oyes; Preséntome, y no me atiendes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 21, 'Haste tornado cruel para mí: Con la fortaleza de tu mano me amenazas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 22, 'Levantásteme, é hicísteme cabalgar sobre el viento, Y disolviste mi sustancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 23, 'Porque yo conozco que me reduces á la muerte; Y á la casa determinada á todo viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 24, 'Mas él no extenderá la mano contra el sepulcro; ¿Clamarán los sepultados cuando él los quebrantare?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 25, '¿No lloré yo al afligido? Y mi alma ¿no se entristeció sobre el menesteroso?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 26, 'Cuando esperaba yo el bien, entonces vino el mal; Y cuando esperaba luz, la oscuridad vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 27, 'Mis entrañas hierven, y no reposan; Días de aflicción me han sobrecogido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 28, 'Denegrido ando, y no por el sol: Levantádome he en la congregación, y clamado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 29, 'He venido á ser hermano de los dragones, Y compañero de los buhos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 30, 'Mi piel está denegrida sobre mí, Y mis huesos se secaron con ardentía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 30, 31, 'Y hase tornado mi arpa en luto, Y mi órgano en voz de lamentadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 1, 'HICE pacto con mis ojos: ¿Cómo pues había yo de pensar en virgen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 2, 'Porque ¿qué galardón me daría de arriba Dios, Y qué heredad el Omnipotente de las alturas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 3, '¿No hay quebrantamiento para el impío, Y extrañamiento para los que obran iniquidad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 4, '¿No ve él mis caminos, Y cuenta todos mis pasos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 5, 'Si anduve con mentira, Y si mi pie se apresuró á engaño,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 6, 'Péseme Dios en balanzas de justicia, Y conocerá mi integridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 7, 'Si mis pasos se apartaron del camino, Y si mi corazón se fué tras mis ojos, Y si algo se apegó á mis manos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 8, 'Siembre yo, y otro coma, Y mis verduras sean arrancadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 9, 'Si fué mi corazón engañado acerca de mujer, Y si estuve acechando á la puerta de mi prójimo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 10, 'Muela para otro mi mujer, Y sobre ella otros se encorven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 11, 'Porque es maldad é iniquidad, Que han de castigar los jueces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 12, 'Porque es fuego que devoraría hasta el sepulcro, Y desarraigaría toda mi hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 13, 'Si hubiera tenido en poco el derecho de mi siervo y de mi sierva, Cuando ellos pleitearan conmigo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 14, '¿Qué haría yo cuando Dios se levantase? Y cuando él visitara, ¿qué le respondería yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 15, 'El que en el vientre me hizo á mí, ¿no lo hizo á él? ¿Y no nos dispuso uno mismo en la matriz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 16, 'Si estorbé el contento de los pobres, E hice desfallecer los ojos de la viuda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 17, 'Y si comí mi bocado solo, Y no comió de él el huerfano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 18, '(Porque desde mi mocedad creció conmigo como con padre, Y desde el vientre de mi madre fuí guía de la viuda;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 19, 'Si he visto que pereciera alguno sin vestido, Y al menesteroso sin cobertura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 20, 'Si no me bendijeron sus lomos, Y del vellón de mis ovejas se calentaron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 21, 'Si alcé contra el huérfano mi mano, Aunque viese que me ayudarían en la puerta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 22, 'Mi espalda se caiga de mi hombro, Y mi brazo sea quebrado de mi canilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 23, 'Porque temí el castigo de Dios, Contra cuya alteza yo no tendría poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 24, 'Si puse en oro mi esperanza, Y dije al oro: Mi confianza eres tú;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 25, 'Si me alegré de que mi hacienda se multiplicase, Y de que mi mano hallase mucho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 26, 'Si he mirado al sol cuando resplandecía, Y á la luna cuando iba hermosa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 27, 'Y mi corazón se engañó en secreto, Y mi boca besó mi mano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 28, 'Esto también fuera maldad juzgada; Porque habría negado al Dios soberano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 29, 'Si me alegré en el quebrantamiento del que me aborrecía, Y me regocijé cuando le halló el mal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 30, '(Que ni aun entregué al pecado mi paladar, Pidiendo maldición para su alma;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 31, 'Cuando mis domésticos decían: ¡Quién nos diese de su carne! nunca nos hartaríamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 32, 'El extranjero no tenía fuera la noche; Mis puertas abría al caminante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 33, 'Si encubrí, como los hombres mis prevaricaciones, Escondiendo en mi seno mi iniquidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 34, 'Porque quebrantaba á la gran multitud, Y el menosprecio de las familias me atemorizó, Y callé, y no salí de mi puerta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 35, '¡Quién me diera quien me oyese! He aquí mi impresión es que el Omnipotente testificaría por mí, Aunque mi adversario me hiciera el proceso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 36, 'Ciertamente yo lo llevaría sobre mi hombro, Y me lo ataría en lugar de corona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 37, 'Yo le contaría el número de mis pasos, Y como príncipe me llegaría á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 38, 'Si mi tierra clama contra mí, Y lloran todos sus surcos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 39, 'Si comí su sustancia sin dinero, O afligí el alma de sus dueños;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 31, 40, 'En lugar de trigo me nazcan abrojos, Y espinas en lugar de cebada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 1, 'Y CESARON estos tres varones de responder á Job, por cuanto él era justo en sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 2, 'Entonces Eliú hijo de Barachêl, Bucita, de la familia de Ram, se enojó con furor contra Job: enojóse con furor, por cuanto justificaba su vida más que á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 3, 'Enojóse asimismo con furor contra sus tres amigos, porque no hallaban qué responder, aunque habían condenado á Job.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 4, 'Y Eliú había esperado á Job en la disputa, porque eran más viejos de días que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 5, 'Empero viendo Eliú que no había respuesta en la boca de aquelllos tres varones, su furor se encendió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 6, 'Y respondió Eliú hijo de Barachêl, Buzita, y dijo: Yo soy menor de días y vosotros viejos; He tenido por tanto miedo, y temido declararos mi opinión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 7, 'Yo decía: Los días hablarán, Y la muchedumbre de años declarará sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 8, 'Ciertamente espíritu hay en el hombre, E inspiración del Omnipotente los hace que entiendan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 9, 'No los grandes son los sabios, Ni los viejos entienden el derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 10, 'Por tanto yo dije: Escuchadme; Declararé yo también mi sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 11, 'He aquí yo he esperado á vuestras razones, He escuchado vuestros argumentos, En tanto que buscabais palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 12, 'Os he pues prestado atención, Y he aquí que no hay de vosotros quien redarguya á Job, Y responda á sus razones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 13, 'Porque no digáis: Nosotros hemos hallado sabiduría: Lanzólo Dios, no el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 14, 'Ahora bien, Job no enderezó á mí sus palabras, Ni yo le responderé con vuestras razones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 15, 'Espantáronse, no respondieron más; Fuéronseles los razonamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 16, 'Yo pues he esperado, porque no hablaban, Antes pararon, y no respondieron más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 17, 'Por eso yo también responderé mi parte, También yo declararé mi juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 18, 'Porque lleno estoy de palabras, Y el espíritu de mi vientre me constriñe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 19, 'De cierto mi vientre está como el vino que no tiene respiradero, Y se rompe como odres nuevos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 20, 'Hablaré pues y respiraré; Abriré mis labios, y responderé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 21, 'No haré ahora acepción de personas, Ni usaré con hombre de lisonjeros títulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 32, 22, 'Porque no sé hablar lisonjas: De otra manera en breve mi Hacedor me consuma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 1, 'POR tanto, Job, oye ahora mis razones, Y escucha todas mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 2, 'He aquí yo abriré ahora mi boca, Y mi lengua hablará en mi garganta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 3, 'Mis razones declararán la rectitud de mi corazón, Y mis labios proferirán pura sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 4, 'El espíritu de Dios me hizo, Y la inspiración del Omnipotente me dió vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 5, 'Si pudieres, respóndeme: Dispón tus palabras, está delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 6, 'Heme aquí á mí en lugar de Dios, conforme á tu dicho: De lodo soy yo también formado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 7, 'He aquí que mi terror no te espantará, Ni mi mano se agravará sobre ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 8, 'De cierto tú dijiste á oídos míos, Y yo oí la voz de tus palabras que decían:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 9, 'Yo soy limpio y sin defecto; Y soy inocente, y no hay maldad en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 10, 'He aquí que él buscó achaques contra mí, Y me tiene por su enemigo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 11, 'Puso mis pies en el cepo, Y guardó todas mis sendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 12, 'He aquí en esto no has hablado justamente: Yo te responderé que mayor es Dios que el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 13, '¿Por qué tomaste pleito contra él? Porque él no da cuenta de ninguna de sus razones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 14, 'Sin embargo, en una ó en dos maneras habla Dios; Mas el hombre no entiende.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 15, 'Por sueño de visión nocturna, Cuando el sueño cae sobre los hombres, Cuando se adormecen sobre el lecho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 16, 'Entonces revela al oído de los hombres, Y les señala su consejo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 17, 'Para quitar al hombre de su obra, Y apartar del varón la soberbia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 18, 'Detendrá su alma de corrupción, Y su vida de que pase á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 19, 'También sobre su cama es castigado Con dolor fuerte en todos sus huesos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 20, 'Que le hace que su vida aborrezca el pan, Y su alma la comida suave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 21, 'Su carne desfallece sin verse, Y sus huesos, que antes no se veían, aparecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 22, 'Y su alma se acerca al sepulcro, Y su vida á los que causan la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 23, 'Si tuviera cerca de él Algún elocuente anunciador muy escogido, Que anuncie al hombre su deber;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 24, 'Que le diga que Dios tuvo de él misericordia, Que lo libró de descender al sepulcro, Que halló redención:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 25, 'Enterneceráse su carne más que de niño, Volverá á los días de su mocedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 26, 'Orará á Dios, y le amará, Y verá su faz con júbilo: Y él restituirá al hombre su justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 27, 'El mira sobre los hombres; y el que dijere: Pequé, y pervertí lo recto, Y no me ha aprovechado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 28, 'Dios redimirá su alma, que no pase al sepulcro, Y su vida se verá en luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 29, 'He aquí, todas estas cosas hace Dios Dos y tres veces con el hombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 30, 'Para apartar su alma del sepulcro, Y para iluminarlo con la luz de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 31, 'Escucha, Job, y óyeme; Calla, y yo hablaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 32, 'Que si tuvieres razones, respóndeme; Habla, porque yo te quiero justificar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 33, 33, 'Y si no, óyeme tú á mí; Calla, y enseñarte he sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 1, 'ADEMAS respondió Eliú, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 2, 'Oid, sabios, mis palabras; Y vosotros, doctos, estadme atentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 3, 'Porque el oído prueba las palabras, Como el paladar gusta para comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 4, 'Escojamos para nosotros el juicio, Conozcamos entre nosotros cuál sea lo bueno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 5, 'Porque Job ha dicho: Yo soy justo, Y Dios me ha quitado mi derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 6, '¿He de mentir yo contra mi razón? Mi saeta es gravosa sin haber yo prevaricado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 7, '¿Qué hombre hay como Job, Que bebe el escarnio como agua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 8, 'Y va en compañía con los que obran iniquidad, Y anda con los hombres maliciosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 9, 'Porque ha dicho: De nada servirá al hombre El conformar su voluntad con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 10, 'Por tanto, varones de seso, oidme; Lejos esté de Dios la impiedad, Y del Omnipotente la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 11, 'Porque él pagará al hombre según su obra, Y él le hará hallar conforme á su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 12, 'Sí, por cierto, Dios no hará injusticia, Y el Omnipotente no pervertirá el derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 13, '¿Quién visitó por él la tierra? ¿Y quién puso en orden todo el mundo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 14, 'Si él pusiese sobre el hombre su corazón, Y recogiese así su espíritu y su aliento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 15, 'Toda carne perecería juntamente, Y el hombre se tornaría en polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 16, 'Si pues hay en ti entendimiento, oye esto: Escucha la voz de mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 17, '¿Enseñorearáse el que aborrece juicio? ¿Y condenarás tú al que es tan justo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 18, '¿Hase de decir al rey: Perverso; Y á los príncipes: Impíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 19, '¿Cuánto menos á aquel que no hace acepción de personas de príncipes, Ni el rico es de él más respetado que el pobre? Porque todos son obras de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 20, 'En un momento morirán, y á media noche Se alborotarán los pueblos, y pasarán, Y sin mano será quitado el poderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 21, 'Porque sus ojos están sobre los caminos del hombre, Y ve todos sus pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 22, 'No hay tinieblas ni sombra de muerte Donde se encubran los que obran maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 23, 'No carga pues él al hombre más de lo justo, Para que vaya con Dios á juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 24, 'El quebrantará á los fuertes sin pesquisa, Y hará estar otros en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 25, 'Por tanto él hará notorias las obras de ellos, Cuando los trastornará en la noche, y serán quebrantados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 26, 'Como á malos los herirá En lugar donde sean vistos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 27, 'Por cuanto así se apartaron de él, Y no consideraron todos sus caminos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 28, 'Haciendo venir delante de él el clamor del pobre, Y que oiga el clamor de los necesitados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 29, 'Y si él diere reposo, ¿quién inquietará? Si escondiere el rostro, ¿quién lo mirará? Esto sobre una nación, y lo mismo sobre un hombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 30, 'Haciendo que no reine el hombre hipócrita Para vejaciones del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 31, 'De seguro conviene se diga á Dios: Llevado he ya castigo, no más ofenderé:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 32, 'Enséñame tú lo que yo no veo: Que si hice mal, no lo haré más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 33, '¿Ha de ser eso según tu mente? El te retribuirá, ora rehuses, Ora aceptes, y no yo: Di si no, lo que tú sabes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 34, 'Los hombres de seso dirán conmigo, Y el hombre sabio me oirá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 35, 'Que Job no habla con sabiduría, Y que sus palabras no son con entendimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 36, 'Deseo yo que Job sea probado ampliamente, A causa de sus respuestas por los hombres inicuos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 34, 37, 'Porque á su pecado añadió impiedad: Bate las manos entre nosotros, Y contra Dios multiplica sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 1, 'Y PROCEDIENDO Eliú en su razonamiento, dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 2, '¿Piensas ser conforme á derecho Esto que dijiste: Más justo soy yo que Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 3, 'Porque dijiste: ¿Qué ventaja sacarás tú de ello? ¿O qué provecho tendré de mi pecado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 4, 'Yo te responderé razones, Y á tus compañeros contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 5, 'Mira á los cielos, y ve, Y considera que las nubes son más altas que tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 6, 'Si pecares, ¿qué habrás hecho contra él? Y si tus rebeliones se multiplicaren, ¿qué le harás tú?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 7, 'Si fueres justo, ¿qué le darás á el? ¿O qué recibirá de tu mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 8, 'Al hombre como tú dañará tu impiedad, Y al hijo del hombre aprovechará tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 9, 'A causa de la multitud de las violencias clamarán, Y se lamentarán por el poderío de los grandes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 10, 'Y ninguno dice: ¿Dónde está Dios mi Hacedor, Que da canciones en la noche,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 11, 'Que nos enseña más que á las bestias de la tierra, Y nos hace sabios más que las aves del cielo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 12, 'Allí clamarán, y él no oirá, Por la soberbia de los malos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 13, 'Ciertamente Dios no oirá la vanidad, Ni la mirará el Omnipotente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 14, 'Aunque más digas, No lo mirará; Haz juicio delante de él, y en él espera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 15, 'Mas ahora, porque en su ira no visita, Ni conoce con rigor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 35, 16, '(35-15) Por eso Job abrió su boca vanamente, Y multiplica palabras sin sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 1, 'Y AñADIO Eliú, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 2, 'Espérame un poco, y enseñarte he; Porque todavía tengo razones en orden á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 3, 'Tomaré mi noticia de lejos, Y atribuiré justicia á mi Hacedor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 4, 'Porque de cierto no son mentira mis palabras; Contigo está el que es íntegro en sus conceptos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 5, 'He aquí que Dios es grande, mas no desestima á nadie; Es poderoso en fuerza de sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 6, 'No otorgará vida al impío, Y á los afligidos dará su derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 7, 'No quitará sus ojos del justo; Antes bien con los reyes los pondrá en solio para siempre, Y serán ensalzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 8, 'Y si estuvieren prendidos en grillos, Y aprisionados en las cuerdas de aflicción,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 9, 'El les dará á conocer la obra de ellos, Y que prevalecieron sus rebeliones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 10, 'Despierta además el oído de ellos para la corrección, Y díce les que se conviertan de la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 11, 'Si oyeren, y le sirvieren, Acabarán sus días en bien, y sus años en deleites.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 12, 'Mas si no oyeren, serán pasados á cuchillo, Y perecerán sin sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 13, 'Empero los hipócritas de corazón lo irritarán más, Y no clamarán cuando él los atare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 14, 'Fallecerá el alma de ellos en su mocedad, Y su vida entre los sodomitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 15, 'Al pobre librará de su pobreza, Y en la aflicción despertará su oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 16, 'Asimismo te apartaría de la boca de la angustia A lugar espacioso, libre de todo apuro; Y te asentará mesa llena de grosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 17, 'Mas tú has llenado el juicio del impío, En vez de sustentar el juicio y la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 18, 'Por lo cual teme que en su ira no te quite con golpe, El cual no puedas apartar de ti con gran rescate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 19, '¿Hará él estima de tus riquezas, ni del oro, Ni de todas las fuerzas del poder?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 20, 'No anheles la noche, En que desaparecen los pueblos de su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 21, 'Guárdate, no tornes á la iniquidad; Pues ésta escogiste más bien que la aflicción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 22, 'He aquí que Dios es excelso con su potencia; ¿Qué enseñador semejante á él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 23, '¿Quién le ha prescrito su camino? ¿Y quién le dirá: Iniquidad has hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 24, 'Acuérdate de engrandecer su obra, La cual contemplan los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 25, 'Los hombres todos la ven; Mírala el hombre de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 26, 'He aquí, Dios es grande, y nosotros no le conocemos; Ni se puede rastrear el número de sus años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 27, 'El reduce las gotas de las aguas, Al derramarse la lluvia según el vapor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 28, 'Las cuales destilan las nubes, Goteando en abundancia sobre los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 29, '¿Quién podrá tampoco comprender la extensión de las nubes, Y el sonido estrepitoso de su pabellón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 30, 'He aquí que sobre él extiende su luz, Y cobija con ella las raíces de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 31, 'Bien que por esos medios castiga á los pueblos, A la multitud da comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 32, 'Con las nubes encubre la luz, Y mándale no brillar, interponiendo aquéllas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 36, 33, 'Tocante á ella anunciará el trueno, su compañero, Que hay acumulación de ira sobre el que se eleva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 1, 'A ESTO también se espanta mi corazón, Y salta de su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 2, 'Oid atentamente su voz terrible, y el sonido que sale de su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 3, 'Debajo de todos los cielos lo dirige, Y su luz hasta los fines de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 4, 'Después de ella bramará el sonido, Tronará él con la voz de su magnificencia; Y aunque sea oída su voz, no los detiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 5, 'Tronará Dios maravillosamente con su voz; El hace grandes cosas, que nosotros no entendemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 6, 'Porque á la nieve dice: Desciende á la tierra; También á la llovizna, Y á los aguaceros de su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 7, 'Así hace retirarse á todo hombre, Para que los hombres todos reconozcan su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 8, 'La bestia se entrará en su escondrijo, Y estaráse en sus moradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 9, 'Del mediodía viene el torbellino, Y el frío de los vientos del norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 10, 'Por el soplo de Dios se da el hielo, Y las anchas aguas son constreñidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 11, 'Regando también llega á disipar la densa nube, Y con su luz esparce la niebla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 12, 'Asimismo por sus designios se revuelven las nubes en derredor, Para hacer sobre la haz del mundo, En la tierra, lo que él les mandara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 13, 'Unas veces por azote, otras pos causa de su tierra, Otras por misericordia las hará parecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 14, 'Escucha esto, Job; Repósate, y considera las maravillas de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 15, '¿Supiste tú cuándo Dios las ponía en concierto, Y hacía levantar la luz de su nube?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 16, '¿Has tú conocido las diferencias de las nubes, Las maravillas del Perfecto en sabiduría?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 17, '¿Por qué están calientes tus vestidos Cuando se fija el viento del mediodía sobre la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 18, '¿Extendiste tú con él los cielos, Firmes como un espejo sólido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 19, 'Muéstranos qué le hemos de decir; Porque nosotros no podemos componer las ideas á causa de las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 20, '¿Será preciso contarle cuando yo hablaré? Por más que el hombre razone, quedará como abismado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 21, 'He aquí aún: no se puede mirar la luz esplendente en los cielos, Luego que pasa el viento y los limpia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 22, 'Viniendo de la parte del norte la dorada claridad. En Dios hay una majestad terrible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 23, 'El es Todopoderoso, al cual no alcanzamos, grande en potencia; Y en juicio y en multitud de justicia no afligirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 37, 24, 'Temerlo han por tanto los hombres: El no mira á los sabios de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 1, 'Y RESPONDIO Jehová á Job desde un torbellino, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 2, '¿Quién es ése que oscurece el consejo Con palabras sin sabiduría?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 3, 'Ahora ciñe como varón tus lomos; Yo te preguntaré, y hazme saber tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 4, '¿Dónde estabas cuando yo fundaba la tierra? Házme lo saber, si tienes inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 5, '¿Quién ordenó sus medidas, si lo sabes? ¿O quién extendió sobre ella cordel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 6, '¿Sobre qué están fundadas sus basas? ¿O quién puso su piedra angular,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 7, 'Cuando las estrellas todas del alba alababan, Y se regocijaban todos los hijos de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 8, '¿Quién encerró con puertas la mar, Cuando se derramaba por fuera como saliendo de madre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 9, 'Cuando puse yo nubes por vestidura suya, Y por su faja oscuridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 10, 'Y establecí sobre ella mi decreto, Y le puse puertas y cerrojo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 11, 'Y dije: Hasta aquí vendrás, y no pasarás adelante, Y ahí parará la hinchazón de tus ondas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 12, '¿Has tu mandado á la mañana en tus días? ¿Has mostrado al alba su lugar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 13, 'Para que ocupe los fines de la tierra, Y que sean sacudidos de ella los impíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 14, 'Trasmúdase como lodo bajo de sello, Y viene á estar como con vestidura:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 15, 'Mas la luz de los impíos es quitada de ellos, Y el brazo enaltecido es quebrantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 16, '¿Has entrado tú hasta los profundos de la mar, Y has andado escudriñando el abismo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 17, '¿Hante sido descubiertas las puertas de la muerte, Y has visto las puertas de la sombra de muerte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 18, '¿Has tú considerado hasta las anchuras de la tierra? Declara si sabes todo esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 19, '¿Por dónde va el camino á la habitación de la luz, Y dónde está el lugar de las tinieblas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 20, '¿Si llevarás tú ambas cosas á sus términos, Y entenderás las sendas de su casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 21, '¿Sabíaslo tú porque hubieses ya nacido, O porque es grande el número de tus días?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 22, '¿Has tú entrado en los tesoros de la nieve, O has visto los tesoros del granizo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 23, 'Lo cual tengo yo reservado para el tiempo de angustia, Para el día de la guerra y de la batalla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 24, '¿Por qué camino se reparte la luz, Y se esparce el viento solano sobre la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 25, '¿Quién repartió conducto al turbión, Y camino á los relámpagos y truenos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 26, 'Haciendo llover sobre la tierra deshabitada, Sobre el desierto, donde no hay hombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 27, 'Para hartar la tierra desierta é inculta, Y para hacer brotar la tierna hierba?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 28, '¿Tiene la lluvia padre? ¿O quién engendró las gotas del rocío?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 29, '¿De qué vientre salió el hielo? Y la escarcha del cielo, ¿quién la engendró?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 30, 'Las aguas se endurecen á manera de piedra, Y congélase la haz del abismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 31, '¿Podrás tú impedir las delicias de las Pléyades, O desatarás las ligaduras del Orión?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 32, '¿Sacarás tú á su tiempo los signos de los cielos, O guiarás el Arcturo con sus hijos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 33, '¿Supiste tú las ordenanzas de los cielos? ¿Dispondrás tú de su potestad en la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 34, '¿Alzarás tú á las nubes tu voz, Para que te cubra muchedumbre de aguas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 35, '¿Enviarás tú los relámpagos, para que ellos vayan? ¿Y diránte ellos: Henos aquí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 36, '¿Quién puso la sabiduría en el interior? ¿O quién dió al entendimiento la inteligencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 37, '¿Quién puso por cuenta los cielos con sabiduría? Y los odres de los cielos, ¿quién los hace parar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 38, 'Cuando el polvo se ha convertido en dureza, Y los terrones se han pegado unos con otros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 39, '(39-1) ¿CAZARAS tú la presa para el león? ¿Y saciarás el hambre de los leoncillos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 40, '(39-2) Cuando están echados en las cuevas, O se están en sus guaridas para acechar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 38, 41, '(39-3) ¿Quién preparó al cuervo su alimento, Cuando sus pollos claman á Dios, Bullendo de un lado á otro por carecer de comida?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 1, '(39-4) ¿Sabes tú el tiempo en que paren las cabras monteses? ¿O miraste tú las ciervas cuando están pariendo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 2, '(39-5) ¿Contaste tú los meses de su preñez, Y sabes el tiempo cuando han de parir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 3, '(39-6) Encórvanse, hacen salir sus hijos, Pasan sus dolores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 4, '(39-7) Sus hijos están sanos, crecen con el pasto: Salen y no vuelven á ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 5, '(39-8) ¿Quién echó libre al asno montés, y quién soltó sus ataduras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 6, '(39-9) Al cual yo puse casa en la soledad, Y sus moradas en lugares estériles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 7, '(39-10) Búrlase de la multitud de la ciudad: No oye las voces del arriero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 8, '(39-11) Lo oculto de los montes es su pasto, Y anda buscando todo lo que está verde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 9, '(39-12) ¿Querrá el unicornio servirte á ti, Ni quedar á tu pesebre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 10, '(39-13) ¿Atarás tú al unicornio con su coyunda para el surco? ¿Labrará los valles en pos de ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 11, '(39-14) ¿Confiarás tú en él, por ser grande su fortaleza, Y le fiarás tu labor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 12, '(39-15) ¿Fiarás de él que te tornará tu simiente, Y que la allegará en tu era?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 13, '(39-16) ¿Diste tú hermosas alas al pavo real, O alas y plumas al avestruz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 14, '(39-17) El cual desampara en la tierra sus huevos, Y sobre el polvo los calienta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 15, '(39-18) Y olvídase de que los pisará el pie, Y que los quebrará bestia del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 16, '(39-19) Endurécese para con sus hijos, como si no fuesen suyos, No temiendo que su trabajo haya sido en vano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 17, '(39-20) Porque le privó Dios de sabiduría, Y no le dió inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 18, '(39-21) Luego que se levanta en alto, Búrlase del caballo y de su jinete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 19, '(39-22) ¿Diste tú al caballo la fortaleza? ¿Vestiste tú su cerviz de relincho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 20, '(39-23) ¿Le intimidarás tú como á alguna langosta? El resoplido de su nariz es formidable:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 21, '(39-24) Escarba la tierra, alégrase en su fuerza, Sale al encuentro de las armas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 22, '(39-25) Hace burla del espanto, y no teme, Ni vuelve el rostro delante de la espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 23, '(39-26) Contra él suena la aljaba, El hierro de la lanza y de la pica:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 24, '(39-27) Y él con ímpetu y furor escarba la tierra, Sin importarle el sonido de la bocina;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 25, '(39-28) Antes como que dice entre los clarines: ¡Ea! Y desde lejos huele la batalla, el grito de los capitanes, y la vocería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 26, '(39-29) ¿Vuela el gavilán por tu industria, Y extiende hacia el mediodía sus alas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 27, '(39-30) ¿Se remonta el águila por tu mandamiento, Y pone en alto su nido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 28, '(39-31) Ella habita y está en la piedra, En la cumbre del peñasco y de la roca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 29, '(39-32) Desde allí acecha la comida: Sus ojos observan de muy lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 39, 30, '(39-33) Sus pollos chupan la sangre: Y donde hubiere cadáveres, allí está.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 1, '(39-34) A más de eso respondió Jehová á Job y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 2, '(39-35) ¿Es sabiduría contender con el Omnipotente? El que disputa con Dios, responda á esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 3, '(39-36) Y respondió Job á Jehová, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 4, '(39-37) He aquí que yo soy vil, ¿qué te responderé? Mi mano pongo sobre mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 5, '(39-38) Una vez hablé, y no responderé: Aun dos veces, mas no tornaré á hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 6, '(40-1) ENTONCES respondió Jehová á Job desde la oscuridad, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 7, '(40-2) Cíñete ahora como varón tus lomos; Yo te preguntaré, y explícame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 8, '(40-3) ¿Invalidarás tú también mi juicio? ¿Me condenarás á mí, para justificarte á ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 9, '(40-4) ¿Tienes tú brazo como Dios? ¿Y tronarás tú con voz como él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 10, '(40-5) Atavíate ahora de majestad y de alteza: Y vístete de honra y de hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 11, '(40-6) Esparce furores de tu ira: Y mira á todo soberbio, y abátelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 12, '(40-7) Mira á todo soberbio, y humíllalo, Y quebranta á los impíos en su asiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 13, '(40-8) Encúbrelos á todos en el polvo, Venda sus rostros en la oscuridad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 14, '(40-9) Y yo también te confesaré Que podrá salvarte tu diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 15, '(40-10) He aquí ahora behemoth, al cual yo hice contigo; Hierba come como buey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 16, '(40-11) He aquí ahora que su fuerza está en sus lomos, Y su fortaleza en el ombligo de su vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 17, '(40-12) Su cola mueve como un cedro, Y los nervios de sus genitales son entretejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 18, '(40-13) Sus huesos son fuertes como bronce, Y sus miembros como barras de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 19, '(40-14) El es la cabeza de los caminos de Dios: El que lo hizo, puede hacer que su cuchillo á él se acerque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 20, '(40-15) Ciertamente los montes producen hierba para él: Y toda bestia del campo retoza allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 21, '(40-16) Echaráse debajo de las sombras, En lo oculto de las cañas, y de los lugares húmedos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 22, '(40-17) Los árboles sombríos lo cubren con su sombra; Los sauces del arroyo lo cercan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 23, '(40-18) He aquí que él tomará el río sin inmutarse: Y confíase que el Jordán pasará por su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 40, 24, '(40-19) ¿Tomarálo alguno por sus ojos en armadijos, Y horadará su nariz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 1, '¿SACARAS tú al leviathán con el anzuelo, O con la cuerda que le echares en su lengua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 2, '¿Pondrás tú garfio en sus narices, Y horadarás con espinas su quijada?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 3, '¿Multiplicará él ruegos para contigo? ¿Hablaráte él lisonjas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 4, '¿Hará concierto contigo Para que lo tomes por siervo perpetuo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 5, '¿Jugarás tú con él como con pájaro, O lo atarás para tus niñas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 6, '¿Harán de él banquete los compañeros? ¿Partiránlo entre los mercaderes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 7, '¿Cortarás tú con cuchillo su cuero, O con asta de pescadores su cabeza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 8, 'Pon tu mano sobre él; Te acordarás de la batalla, y nunca más tornarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 9, 'He aquí que la esperanza acerca de él será burlada; Porque aun á su sola vista se desmayarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 10, 'Nadie hay tan osado que lo despierte: ¿Quién pues podrá estar delante de mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 11, '¿Quién me ha anticipado, para que yo restituya? Todo lo que hay debajo del cielo es mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 12, 'Yo no callaré sus miembros, Ni lo de sus fuerzas y la gracia de su disposición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 13, '¿Quién descubrirá la delantera de su vestidura? ¿Quién se llegará á él con freno doble?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 14, '¿Quién abrirá las puertas de su rostro? Los órdenes de sus dientes espantan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 15, 'La gloria de su vestido son escudos fuertes, Cerrados entre sí estrechamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 16, 'El uno se junta con el otro, Que viento no entra entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 17, 'Pegado está el uno con el otro, Están trabados entre sí, que no se pueden apartar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 18, 'Con sus estornudos encienden lumbre, Y sus ojos son como los párpados del alba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 19, 'De su boca salen hachas de fuego, Centellas de fuego proceden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 20, 'De sus narices sale humo, Como de una olla ó caldero que hierve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 21, 'Su aliento enciende los carbones, Y de su boca sale llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 22, 'En su cerviz mora la fortaleza, Y espárcese el desaliento delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 23, 'Las partes momias de su carne están apretadas: Están en él firmes, y no se mueven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 24, 'Su corazón es firme como una piedra, Y fuerte como la muela de abajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 25, 'De su grandeza tienen temor los fuertes, Y á causa de su desfallecimiento hacen por purificarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 26, 'Cuando alguno lo alcanzare, ni espada, Ni lanza, ni dardo, ni coselete durará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 27, 'El hierro estima por pajas, Y el acero por leño podrido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 28, 'Saeta no le hace huir; Las piedras de honda se le tornan aristas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 29, 'Tiene toda arma por hojarascas, Y del blandir de la pica se burla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 30, 'Por debajo tiene agudas conchas; Imprime su agudez en el suelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 31, 'Hace hervir como una olla la profunda mar, Y tórnala como una olla de ungüento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 32, 'En pos de sí hace resplandecer la senda, Que parece que la mar es cana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 33, 'No hay sobre la tierra su semejante, Hecho para nada temer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 41, 34, 'Menosprecia toda cosa alta: Es rey sobre todos los soberbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 1, 'Y RESPONDIO Job á Jehová, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 2, 'Yo conozco que todo lo puedes, Y que no hay pensamiento que se esconda de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 3, '¿Quién es el que oscurece el consejo sin ciencia? Por tanto yo denunciaba lo que no entendía; Cosas que me eran ocultas, y que no las sabía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 4, 'Oye te ruego, y hablaré; Te preguntaré, y tú me enseñarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 5, 'De oídas te había oído; Mas ahora mis ojos te ven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 6, 'Por tanto me aborrezco, y me arrepiento En el polvo y en la ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 7, 'Y aconteció que después que habló Jehová estas palabras á Job, Jehová dijo á Eliphaz Temanita: Mi ira se encendió contra ti y tus dos compañeros: porque no habéis hablado por mí lo recto, como mi siervo Job.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 8, 'Ahora pues, tomaos siete becerros y siete carneros, y andad á mi siervo Job, y ofreced holocausto por vosotros, y mi siervo Job orará por vosotros; porque de cierto á él atenderé para no trataros afrentosamente, por cuanto no habéis hablado por mí con rectitud, como mi siervo Job.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 9, 'Fueron pues Eliphaz Temanita, y Bildad Suhita, y Sophar Naamatita, é hicieron como Jehová les dijo: y Jehová atendió á Job.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 10, 'Y mudó Jehová la aflicción de Job, orando él por sus amigos: y aumentó al doble todas las cosas que habían sido de Job.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 11, 'Y vinieron é él todos sus hermanos, y todas sus hermanas, y todos los que antes le habían conocido, y comieron con él pan en su casa, y condoliéronse de él, y consoláronle de todo aquel mal que sobre él había Jehová traído; y cada uno de ellos le dió una pieza de moneda, y un zarcillo de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 12, 'Y bendijo Jehová la postrimería de Job más que su principio; porque tuvo catorce mil ovejas, y seis mil camellos, y mil yuntas de bueyes, y mil asnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 13, 'Y tuvo siete hijos y tres hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 14, 'Y llamó el nombre de la una, Jemimah, y el nombre de la segunda, Cesiah, y el nombre de la tercera, Keren-happuch.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 15, 'Y no se hallaron mujeres tan hermosas como las hijas de Job en toda la tierra: y dióles su padre herencia entre sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 16, 'Y después de esto vivió Job ciento y cuarenta años, y vió á sus hijos, y á los hijos de sus hijos, hasta la cuarta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOB', 'Job', 42, 17, 'Murió pues Job viejo, y lleno de días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 1, 'PALABRAS del Predicador, hijo de David, rey en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 2, 'Vanidad de vanidades, dijo el Predicador; vanidad de vanidades, todo vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 3, '¿Qué provecho tiene el hombre de todo su trabajo con que se afana debajo del sol?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 4, 'Generación va, y generación viene: mas la tierra siempre permanece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 5, 'Y sale el sol, y pónese el sol, y con deseo vuelve á su lugar donde torna á nacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 6, 'El viento tira hacia el mediodía, y rodea al norte; va girando de continuo, y á sus giros torna el viento de nuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 7, 'Los ríos todos van á la mar, y la mar no se hinche; al lugar de donde los ríos vinieron, allí tornan para correr de nuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 8, 'Todas las cosas andan en trabajo mas que el hombre pueda decir: ni los ojos viendo se hartan de ver, ni los oídos se hinchen de oir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 9, '¿Qué es lo que fué? Lo mismo que será. ¿Qué es lo que ha sido hecho? Lo mismo que se hará: y nada hay nuevo debajo del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 10, '¿Hay algo de que se pueda decir: He aquí esto es nuevo? Ya fué en los siglos que nos han precedido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 11, 'No hay memoria de lo que precedió, ni tampoco de lo que sucederá habrá memoria en los que serán después.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 12, 'Yo el Predicador fuí rey sobre Israel en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 13, 'Y dí mi corazón á inquirir y buscar con sabiduría sobre todo lo que se hace debajo del cielo: este penoso trabajo dió Dios á los hijos de los hombres, en que se ocupen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 14, 'Yo miré todas las obras que se hacen debajo del sol; y he aquí, todo ello es vanidad y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 15, 'Lo torcido no se puede enderezar; y lo falto no puede contarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 16, 'Hablé yo con mi corazón, diciendo: He aquí hállome yo engrandecido, y he crecido en sabiduría sobre todos los que fueron antes de mí en Jerusalem; y mi corazón ha percibido muchedumbre de sabiduría y ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 17, 'Y dí mi corazón á conocer la sabiduría, y también á entender las locuras y los desvaríos: conocí que aun esto era aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 1, 18, 'Porque en la mucha sabiduría hay mucha molestia; y quien añade ciencia, añade dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 1, 'DIJE yo en mi corazón: Ven ahora, te probaré con alegría, y gozarás de bienes. Mas he aquí esto también era vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 2, 'A la risa dije: Enloqueces; y al placer: ¿De qué sirve esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 3, 'Propuse en mi corazón agasajar mi carne con vino, y que anduviese mi corazón en sabiduría, con retención de la necedad, hasta ver cuál fuese el bien de los hijos de los hombres, en el cual se ocuparan debajo del cielo todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 4, 'Engrandecí mis obras, edifiquéme casas, plantéme viñas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 5, 'Híceme huertos y jardines, y planté en ellos árboles de todos frutos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 6, 'Híceme estanques de aguas, para regar de ellos el bosque donde los árboles crecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 7, 'Poseí siervos y siervas, y tuve hijos de familia; también tuve posesión grande de vacas y ovejas, sobre todos los que fueron antes de mí en Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 8, 'Alleguéme también plata y oro, y tesoro preciado de reyes y de provincias; híceme de cantores y cantoras, y los deleites de los hijos de los hombres, instrumentos músicos y de todas suertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 9, 'Y fuí engrandecido, y aumentado más que todos los que fueron antes de mí en Jerusalem: á más de esto perseveró conmigo mi sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 10, 'No negué á mis ojos ninguna cosa que desearan, ni aparté mi corazón de placer alguno, porque mi corazón gozó de todo mi trabajo: y ésta fué mi parte de toda mi faena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 11, 'Miré yo luego todas las obras que habían hecho mis manos, y el trabajo que tomé para hacer las: y he aquí, todo vanidad y aflicción de espíritu, y no hay provecho debajo del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 12, 'Después torné yo á mirar para ver la sabiduría y los desvaríos y la necedad; (porque ¿qué hombre hay que pueda seguir al rey en lo que ya hicieron?)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 13, 'Y he visto que la sabiduría sobrepuja á la necedad, como la luz á las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 14, 'El sabio tiene sus ojos en su cabeza, mas el necio anda en tinieblas: empero también entendí yo que un mismo suceso acaecerá al uno que al otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 15, 'Entonces dije yo en mi corazón: Como sucederá al necio me sucederá también á mí: ¿para qué pues he trabajado hasta ahora por hacerme más sabio? Y dije en mi corazón, que también esto era vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 16, 'Porque ni del sabio ni del necio habrá memoria para siempre; pues en los días venideros ya todo será olvidado, y también morirá el sabio como el necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 17, 'Aborrecí por tanto la vida, porque la obra que se hace debajo del sol me era fastidiosa; por cuanto todo es vanidad y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 18, 'Yo asimismo aborrecí todo mi trabajo que había puesto por obra debajo del sol; el cual dejaré á otro que vendrá después de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 19, '¿Y quién sabe si será sabio, ó necio, el que se enseñoreará de todo mi trabajo en que yo me afané, y en que ocupé debajo del sol mi sabiduría? Esto también es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 20, 'Tornéme por tanto á desesperanzar mi corazón acerca de todo el trabajo en que me afané, y en que había ocupado debajo del sol mi sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 21, '¡Que el hombre trabaje con sabiduría, y con ciencia, y con rectitud, y que haya de dar su hacienda á hombre que nunca trabajó en ello! También es esto vanidad y mal grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 22, 'Porque ¿qué tiene el hombre de todo su trabajo, y fatiga de su corazón, con que debajo del sol él se afanara?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 23, 'Porque todos sus días no son sino dolores, y sus trabajos molestias: aun de noche su corazón no reposa. Esto también es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 24, 'No hay cosa mejor para el hombre sino que coma y beba, y que su alma vea el bien de su trabajo. También tengo yo visto que esto es de la mano de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 25, 'Porque ¿quién comerá, y quién se cuidará, mejor que yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 2, 26, 'Porque al hombre que le agrada, Dios le da sabiduría y ciencia y gozo, mas al pecador da trabajo, el que allegue y amontone, para que dé al que agrada á Dios. También esto es vanidad y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 1, 'PARA todas las cosas hay sazón, y todo lo que se quiere debajo del cielo, tiene su tiempo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 2, 'Tiempo de nacer, y tiempo de morir; tiempo de plantar, y tiempo de arrancar lo plantado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 3, 'Tiempo de matar, y tiempo de curar; tiempo de destruir, y tiempo de edificar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 4, 'Tiempo de llorar, y tiempo de reir; tiempo de endechar, y tiempo de bailar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 5, 'Tiempo de esparcir las piedras, y tiempo de allegar las piedras; tiempo de abrazar, y tiempo de alejarse de abrazar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 6, 'Tiempo de agenciar, y tiempo de perder; tiempo de guardar, y tiempo de arrojar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 7, 'Tiempo de romper, y tiempo de coser; tiempo de callar, y tiempo de hablar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 8, 'Tiempo de amar, y tiempo de aborrecer; tiempo de guerra, y tiempo de paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 9, '¿Qué provecho tiene el que trabaja en lo que trabaja?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 10, 'Yo he visto el trabajo que Dios ha dado á los hijos de los hombres para que en él se ocupasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 11, 'Todo lo hizo hermoso en su tiempo: y aun el mundo dió en su corazón, de tal manera que no alcance el hombre la obra de Dios desde el principio hasta el cabo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 12, 'Yo he conocido que no hay mejor para ellos, que alegrarse, y hacer bien en su vida:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 13, 'Y también que es don de Dios que todo hombre coma y beba, y goce el bien de toda su labor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 14, 'He entendido que todo lo que Dios hace, ésto será perpetuo: sobre aquello no se añadirá, ni de ello se disminuirá; y hácelo Dios, para que delante de él teman los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 15, 'Aquello que fué, ya es: y lo que ha de ser, fué ya; y Dios restaura lo que pasó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 16, 'Vi más debajo del sol: en lugar del juicio, allí la impiedad; y en lugar de la justicia, allí la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 17, 'Y dije yo en mi corazón: Al justo y al impío juzgará Dios; porque allí hay tiempo á todo lo que se quiere y sobre todo lo que se hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 18, 'Dije en mi corazón, en orden á la condición de los hijos de los hombres, que Dios los probaría, para que así echaran de ver ellos mismos que son semejantes á las bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 19, 'Porque el suceso de los hijos de los hombres, y el suceso del animal, el mismo suceso es: como mueren los unos, así mueren los otros; y una misma respiración tienen todos; ni tiene más el hombre que la bestia: porque todo es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 20, 'Todo va á un lugar: todo es hecho del polvo, y todo se tornará en el mismo polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 21, '¿Quién sabe que el espíritu de los hijos de los hombres suba arriba, y que el espíritu del animal descienda debajo de la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 3, 22, 'Así que he visto que no hay cosa mejor que alegrarse el hombre con lo que hiciere; porque esta es su parte: porque ¿quién lo llevará para que vea lo que ha de ser después de él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 1, 'Y TORNÉME yo, y vi todas las violencias que se hacen debajo del sol: y he aquí las lágrimas de los oprimidos, y sin tener quien los consuele; y la fuerza estaba en la mano de sus opresores, y para ellos no había consolador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 2, 'Y alabé yo los finados que ya murieron, más que los vivientes que hasta ahora están vivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 3, 'Y tuve por mejor que unos y otros al que no ha sido aún, que no ha visto las malas obras que debajo del sol se hacen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 4, 'Visto he asimismo que todo trabajo y toda excelencia de obras mueve la envidia del hombre contra su prójimo. También esto es vanidad y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 5, 'El necio dobla sus manos y come su carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 6, 'Mas vale el un puño lleno con descanso, que ambos puños llenos con trabajo y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 7, 'Yo me torné otra vez, y vi vanidad debajo del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 8, 'Está un hombre solo y sin sucesor; que ni tiene hijo ni hermano; mas nunca cesa de trabajar, ni sus ojos se hartan de sus riquezas, ni se pregunta: ¿Para quién trabajo yo, y defraudo mi alma del bien? También esto es vanidad, y duro trabajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 9, 'Mejores son dos que uno; porque tienen mejor paga de su trabajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 10, 'Porque si cayeren, el uno levantará á su compañero: mas ¡ay del solo! que cuando cayere, no habrá segundo que lo levante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 11, 'También si dos durmieren juntos, se calentarán; mas ¿cómo se calentará uno solo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 12, 'Y si alguno prevaleciere contra el uno, dos estarán contra él; y cordón de tres dobleces no presto se rompe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 13, 'Mejor es el muchacho pobre y sabio, que el rey viejo y fatuo que no sabe ser aconsejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 14, 'Porque de la cárcel salió para reinar; mientras el nacido en su reino se hizo pobre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 15, 'Vi todos los vivientes debajo del sol caminando con el muchacho, sucesor, que estará en lugar de aquél.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 4, 16, 'No tiene fin todo el pueblo que fué antes de ellos: tampoco los que vendrán después estarán con él contentos. Y esto es también vanidad y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 1, 'CUANDO fueres á la casa de Dios, guarda tu pie; y acércate más para oir que para dar el sacrificio de los necios: porque no saben que hacen mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 2, 'No te des priesa con tu boca, ni tu corazón se apresure á proferir palabra delante de Dios; porque Dios está en el cielo, y tú sobre la tierra: por tanto, sean pocas tus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 3, 'Porque de la mucha ocupación viene el sueño, y de la multitud de las palabras la voz del necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 4, 'Cuando á Dios hicieres promesa, no tardes en pagarla; porque no se agrada de los insensatos. Paga lo que prometieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 5, 'Mejor es que no prometas, que no que prometas y no pagues.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 6, 'No sueltes tu boca para hacer pecar á tu carne; ni digas delante del ángel, que fué ignorancia. ¿Por qué harás que Dios se aire á causa de tu voz, y que destruya la obra de tus manos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 7, 'Donde los sueños son en multitud, también lo son las vanidades y muchas las palabras; mas tú teme á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 8, 'Si violencias de pobres, y extorsión de derecho y de justicia vieres en la porvincia, no te maravilles de esta licencia; porque alto está mirando sobre alto, y uno más alto está sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 9, 'Además el provecho de la tierra es para todos: el rey mismo está sujeto á los campos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 10, 'El que ama el dinero, no se hartará de dinero; y el que ama el mucho tener, no sacará fruto. También esto es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 11, 'Cuando los bienes se aumentan, también se aumentan sus comedores. ¿Qué bien, pues, tendrá su dueño, sino ver los con sus ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 12, 'Dulce es el sueño del trabajador, ora coma mucho ó poco; mas al rico no le deja dormir la hartura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 13, 'Hay una trabajosa enfermedad que he visto debajo del sol: las riquezas guardadas de sus dueños para su mal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 14, 'Las cuales se pierden en malas ocupaciones, y á los hijos que engendraron nada les queda en la mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 15, 'Como salió del vientre de su madre, desnudo, así se vuelve, tornando como vino; y nada tuvo de su trabajo para llevar en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 16, 'Este también es un gran mal, que como vino, así haya de volver. ¿Y de qué le aprovechó trabajar al viento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 17, 'Demás de esto, todos los días de su vida comerá en tinieblas, con mucho enojo y dolor y miseria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 18, 'He aquí pues el bien que yo he visto: Que lo bueno es comer y beber, y gozar uno del bien de todo su trabajo con que se fatiga debajo del sol, todos los días de su vida que Dios le ha dado; porque esta es su parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 19, 'Asimismo, á todo hombre á quien Dios dió riquezas y hacienda, y le dió también facultad para que coma de ellas, y tome su parte, y goce su trabajo; esto es don de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 5, 20, 'Porque no se acordará mucho de los días de su vida; pues Dios le responderá con alegría de su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 1, 'HAY un mal que he visto debajo del cielo, y muy común entre los hombres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 2, 'Hombre á quien Dios dió riquezas, y hacienda, y honra, y nada le falta de todo lo que su alma desea; mas Dios no le dió facultad de comer de ello, sino que los extraños se lo comen. Esto vanidad es, y enfermedad trabajosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 3, 'Si el hombre engendrare ciento, y viviere muchos años, y los días de su edad fueren numerosos; si su alma no se hartó del bien, y también careció de sepultura, yo digo que el abortivo es mejor que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 4, 'Porque en vano vino, y á tinieblas va, y con tinieblas será cubierto su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 5, 'Aunque no haya visto el sol, ni conocido nada, más reposo tiene éste que aquél.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 6, 'Porque si viviere aquel mil años dos veces, si no ha gozado del bien, cierto todos van á un lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 7, 'Todo el trabajo del hombre es para su boca, y con todo eso su alma no se harta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 8, 'Porque ¿qué más tiene el sabio que el necio? ¿qué más tiene el pobre que supo caminar entre los vivos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 9, 'Más vale vista de ojos que deseo que pasa. Y también esto es vanidad y aflicción de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 10, 'El que es, ya su nombre ha sido nombrado; y se sabe que es hombre, y que no podrá contender con el que es más fuerte que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 11, 'Ciertamente las muchas palabras multiplican la vanidad. ¿Qué más tiene el hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 6, 12, 'Porque ¿quién sabe cuál es el bien del hombre en la vida, todos los días de la vida de su vanidad, los cuales él pasa como sombra? Porque ¿quién enseñará al hombre qué será después de él debajo del sol?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 1, 'MEJOR es la buena fama que el buen ungüento; y el día de la muerte que el día del nacimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 2, 'Mejor es ir á la casa del luto que á la casa del convite: porque aquello es el fin de todos los hombres; y el que vive parará mientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 3, 'Mejor es el enojo que la risa: porque con la tristeza del rostro se enmendará el corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 4, 'El corazón de los sabios, en la casa del luto; mas el corazón de los insensatos, en la casa del placer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 5, 'Mejor es oir la reprensión del sabio, que la canción de los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 6, 'Porque la risa del necio es como el estrépito de las espinas debajo de la olla. Y también esto es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 7, 'Ciertamente la opresión hace enloquecer al sabio: y el presente corrompe el corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 8, 'Mejor es el fin del negocio que su principio: mejor es el sufrido de espíritu que el altivo de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 9, 'No te apresures en tu espíritu á enojarte: porque la ira en el seno de los necios reposa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 10, 'Nunca digas: ¿Qué es la causa que los tiempos pasados fueron mejores que éstos? Porque nunca de esto preguntarás con sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 11, 'Buena es la ciencia con herencia; y más á los que ven el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 12, 'Porque escudo es la ciencia, y escudo es el dinero: mas la sabiduría excede en que da vida á sus poseedores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 13, 'Mira la obra de Dios; porque ¿quién podrá enderezar lo que él torció?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 14, 'En el día del bien goza del bien; y en el día del mal considera. Dios también hizo esto delante de lo otro, porque el hombre no halle nada tras de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 15, 'Todo esto he visto en los días de mi vanidad. Justo hay que perece por su justicia, y hay impío que por su maldad alarga sus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 16, 'No seas demasiado justo, ni seas sabio con exceso: ¿por qué te destruirás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 17, 'No hagas mal mucho, ni seas insensato: ¿por qué morirás antes de tu tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 18, 'Bueno es que tomes esto, y también de estotro no apartes tu mano; porque el que á Dios teme, saldrá con todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 19, 'La sabiduría fortifica al sabio más que diez poderosos la ciudad en que fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 20, 'Ciertamente no hay hombre justo en la tierra, que haga bien y nunca peque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 21, 'Tampoco apliques tu corazón á todas las cosas que se hablaren, porque no oigas á tu siervo que dice mal de ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 22, 'Porque tu corazón sabe, como tú también dijiste mal de otros muchas veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 23, 'Todas estas cosas probé con sabiduría, diciendo: Hacerme he sabio: mas ella se alejó de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 24, 'Lejos está lo que fué; y lo muy profundo ¿quién lo hallará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 25, 'Yo he rodeado con mi corazón por saber, y examinar, é inquirir la sabiduría, y la razón; y por conocer la maldad de la insensatez, y el desvarío del error;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 26, 'Y yo he hallado más amarga que la muerte la mujer, la cual es redes, y lazos su corazón; sus manos como ligaduras. El que agrada á Dios escapará de ella; mas el pecador será preso en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 27, 'He aquí, esto he hallado, dice el Predicador, pesando las cosas una por una para hallar la razón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 28, 'Lo que aun busca mi alma, y no encuentro: un hombre entre mil he hallado; mas mujer de todas éstas nunca hallé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 7, 29, 'He aquí, solamente he hallado esto: que Dios hizo al hombre recto, mas ellos buscaron muchas cuentas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 1, '¿Quién como el sabio? ¿y quién como el que sabe la declaración de las cosas? La sabiduría del hombre hará relucir su rostro, y mudaráse la tosquedad de su semblante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 2, 'Yo te aviso que guardes el mandamiento del rey y la palabra del juramento de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 3, 'No te apresures á irte de delante de él, ni en cosa mala persistas; porque él hará todo lo que quisiere:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 4, 'Pues la palabra del rey es con potestad, ¿y quién le dirá, Qué haces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 5, 'El que guarda el mandamiento no experimentará mal; y el tiempo y el juicio conoce el corazón del sabio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 6, 'Porque para todo lo que quisieres hay tiempo y juicio; mas el trabajo del hombre es grande sobre él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 7, 'Porque no sabe lo que ha de ser; y el cuándo haya de ser, ¿quién se lo enseñará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 8, 'No hay hombre que tenga potestad sobre el espíritu para retener el espíritu, ni potestad sobre el día de la muerte: y no valen armas en tal guerra; ni la impiedad librará al que la posee.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 9, 'Todo esto he visto, y puesto he mi corazón en todo lo que debajo del sol se hace: hay tiempo en que el hombre se enseñorea del hombre para mal suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 10, 'Esto vi también: que los impíos sepultados vinieron aún en memoria; mas los que partieron del lugar santo, fueron luego puestos en olvido en la ciudad donde con rectitud habían obrado. Esto también es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 11, 'Porque no se ejecuta luego sentencia sobre la mala obra, el corazón de los hijos de los hombres está en ellos lleno para hacer mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 12, 'Bien que el pecador haga mal cien veces, y le sea dilatado el castigo, con todo yo también sé que los que á Dios temen tendrán bien, los que temieren ante su presencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 13, 'Y que el impío no tendrá bien, ni le serán prolongados los días, que son como sombra; por cuanto no temió delante de la presencia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 14, 'Hay vanidad que se hace sobre la tierra: que hay justos á quienes sucede como si hicieran obras de impíos; y hay impíos á quienes acaece como si hicieran obras de justos. Digo que esto también es vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 15, 'Por tanto alabé yo la alegría; que no tiene el hombre bien debajo del sol, sino que coma y beba, y se alegre; y que esto se le quede de su trabajo los días de su vida que Dios le dió debajo del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 16, 'Yo pues dí mi corazón á conocer sabiduría, y á ver la faena que se hace sobre la tierra; (porque hay quien ni de noche ni de día ve sueño en su ojos;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 8, 17, 'Y he visto todas las obras de Dios, que el hombre no puede alcanzar la obra que debajo del sol se hace; por mucho que trabaje el hombre buscándola, no la hallará: aunque diga el sabio que la sabe, no por eso podrá alcanzarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 1, 'CIERTAMENTE dado he mi corazón á todas estas cosas, para declarar todo esto: que los justos y los sabios, y sus obras, están en la mano de Dios; y que no sabe el hombre ni el amor ni el odio por todo lo que pasa delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 2, 'Todo acontece de la misma manera á todos: un mismo suceso ocurre al justo y al impío; al bueno y al limpio y al no limpio; al que sacrifica, y al que no sacrifica: como el bueno, así el que peca; el que jura, como el que teme el juramento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 3, 'Este mal hay entre todo lo que se hace debajo del sol, que todos tengan un mismo suceso, y también que el corazón de los hijos de los hombres esté lleno de mal, y de enloquecimiento en su corazón durante su vida: y después, á los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 4, 'Aún hay esperanza para todo aquél que está entre los vivos; porque mejor es perro vivo que león muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 5, 'Porque los que viven saben que han de morir: mas los muertos nada saben, ni tienen más paga; porque su memoria es puesta en olvido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 6, 'También su amor, y su odio y su envidia, feneció ya: ni tiene ya más parte en el siglo, en todo lo que se hace debajo del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 7, 'Anda, y come tu pan con gozo, y bebe tu vino con alegre corazón: porque tus obras ya son agradables á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 8, 'En todo tiempo sean blancos tus vestidos, y nunca falte ungüento sobre tu cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 9, 'Goza de la vida con la mujer que amas, todos los días de la vida de tu vanidad, que te son dados debajo del sol, todos los días de tu vanidad; porque esta es tu parte en la vida, y en tu trabajo con que te afanas debajo del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 10, 'Todo lo que te viniere á la mano para hacer, hazlo según tus fuerzas; porque en el sepulcro, adonde tú vas, no hay obra, ni industria, ni ciencia, ni sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 11, 'Tornéme, y vi debajo del sol, que ni es de los ligeros la carrera, ni la guerra de los fuertes, ni aun de los sabios el pan, ni de los prudentes las riquezas, ni de los elocuentes el favor; sino que tiempo y ocasión acontece á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 12, 'Porque el hombre tampoco conoce su tiempo: como los peces que son presos en la mala red, y como las aves que se prenden en lazo, así son enlazados los hijos de los hombres en el tiempo malo, cuando cae de repente sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 13, 'También vi esta sabiduría debajo del sol, la cual me parece grande:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 14, 'Una pequeña ciudad, y pocos hombres en ella; y viene contra ella un gran rey, y cércala, y edifica contra ella grandes baluartes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 15, 'Y hállase en ella un hombre pobre, sabio, el cual libra la ciudad con su sabiduría; y nadie se acordaba de aquel pobre hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 16, 'Entonces dije yo: Mejor es la sabiduría que la fortaleza; aunque la ciencia del pobre sea menospreciada, y no sean escuchadas sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 17, 'Las palabras del sabio con reposo son oídas, más que el clamor del señor entre los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 9, 18, 'Mejor es la sabiduría que las armas de guerra; mas un pecador destruye mucho bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 1, 'LAS moscas muertas hacen heder y dar mal olor el perfume del perfumista: así una pequeña locura, al estimado por sabiduría y honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 2, 'El corazón del sabio está á su mano derecha; mas el corazón del necio á su mano izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 3, 'Y aun mientras va el necio por el camino, fálta le, su cordura, y dice á todos, que es necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 4, 'Si el espíritu del príncipe se exaltare contra ti, no dejes tu lugar; porque la lenidad hará cesar grandes ofensas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 5, 'Hay un mal que debajo del sol he visto, á manera de error emanado del príncipe:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 6, 'La necedad está colocada en grandes alturas, y los ricos están sentados en lugar bajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 7, 'Vi siervos en caballos, y príncipes que andaban como siervos sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 8, 'El que hiciere el hoyo caerá en él; y el que aportillare el vallado, morderále la serpiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 9, 'El que mudare las piedras, trabajo tendrá en ellas: el que cortare la leña, en ella peligrará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 10, 'Si se embotare el hierro, y su filo no fuere amolado, hay que añadir entonces más fuerza: empero excede la bondad de la sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 11, 'Muerde la serpiente cuando no está encantada, y el lenguaraz no es mejor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 12, 'Las palabras de la boca del sabio son gracia; mas los labios del necio causan su propia ruina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 13, 'El principio de las palabras de su boca es necedad; y el fin de su charla nocivo desvarío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 14, 'El necio multiplica palabras: no sabe hombre lo que ha de ser; ¿y quién le hará saber lo que después de él será?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 15, 'El trabajo de los necios los fatiga; porque no saben por dónde ir á la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 16, '¡Ay de ti, tierra, cuando tu rey es muchacho, y tus príncipes comen de mañana!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 17, '¡Bienaventurada, tú, tierra, cuando tu rey es hijo de nobles, y tus príncipes comen á su hora, por refección, y no por el beber!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 18, 'Por la pereza se cae la techumbre, y por flojedad de manos se llueve la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 19, 'Por el placer se hace el convite, y el vino alegra los vivos: y el dinero responde á todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 10, 20, 'Ni aun en tu pensamiento digas mal del rey, ni en los secretos de tu cámara digas mal del rico; porque las aves del cielo llevarán la voz, y las que tienen alas harán saber la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 1, 'ECHA tu pan sobre las aguas; que después de muchos días lo hallarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 2, 'Reparte á siete, y aun á ocho: porque no sabes el mal que vendrá sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 3, 'Si las nubes fueren llenas de agua, sobre la tierra la derramarán: y si el árbol cayere al mediodía, ó al norte, al lugar que el árbol cayere, allí quedará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 4, 'El que al viento mira, no sembrará; y el que mira á las nubes, no segará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 5, 'Como tú no sabes cuál es el camino del viento, ó como se crían los huesos en el vientre de la mujer preñada, así ignoras la obra de Dios, el cual hace todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 6, 'Por la mañana siembra tu simiente, y á la tarde no dejes reposar tu mano: porque tú no sabes cuál es lo mejor, si esto ó lo otro, ó si ambas á dos cosas son buenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 7, 'Suave ciertamente es la luz, y agradable á los ojos ver el sol:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 8, 'Mas si el hombre viviere muchos años, y en todos ellos hubiere gozado alegría; si después trajere á la memoria los días de las tinieblas, que serán muchos, todo lo que le habrá pasado, dirá haber sido vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 9, 'Alégrate, mancebo, en tu mocedad, y tome placer tu corazón en los días de tu juventud; y anda en los caminos de tu corazón, y en la vista de tus ojos: mas sabe, que sobre todas estas cosas te traerá Dios á juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 11, 10, 'Quita pues el enojo de tu corazón, y aparta el mal de tu carne: porque la mocedad y la juventud son vainidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 1, 'Y ACUÉRDATE de tu Criador en los días de tu juventud, antes que vengan los malos días, y lleguen los años, de los cuales digas, No tengo en ellos contentamiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 2, 'Antes que se oscurezca el sol, y la luz, y la luna y las estrellas, y las nubes se tornen tras la lluvia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 3, 'Cuando temblarán los guardas de la casa, y se encorvarán los hombres fuertes, y cesarán las muelas, porque han disminuído, y se oscurecerán los que miran por las ventanas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 4, 'Y las puertas de afuera se cerrarán, por la bajeza de la voz de la muela; y levantaráse á la voz del ave, y todas las hijas de canción serán humilladas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 5, 'Cuando también temerán de lo alto, y los tropezones en el camino; y florecerá el almendro, y se agravará la langosta, y perderáse el apetito: porque el hombre va á la casa de su siglo, y los endechadores andarán en derredor por la plaza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 6, 'Antes que la cadena de plata se quiebre, y se rompa el cuenco de oro, y el cántaro se quiebre junto á la fuente, y la rueda sea rota sobre el pozo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 7, 'Y el polvo se torne á la tierra, como era, y el espíritu se vuelva á Dios que lo dió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 8, 'Vanidad de vanidades, dijo el Predicador, todo vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 9, 'Y cuanto más sabio fué el Predicador, tanto más enseñó sabiduría al pueblo; é hizo escuchar, é hizo escudriñar, y compuso muchos proverbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 10, 'Procuró el Predicador hallar palabras agradables, y escritura recta, palabras de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 11, 'Las palabras de los sabios son como aguijones; y como clavos hincados, las de los maestros de las congregaciones, dadas por un Pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 12, 'Ahora, hijo mío, á más de esto, sé avisado. No hay fin de hacer muchos libros; y el mucho estudio aflicción es de la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 13, 'El fin de todo el discurso oído es este: Teme á Dios, y guarda sus mandamientos; porque esto es el todo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ECC', 'Eclesiastés', 12, 14, 'Porque Dios traerá toda obra á juicio, el cual se hará sobre toda cosa oculta, buena ó mala.');
